-- Schema for Domain: route | Business: Transport Shipping | Version: v1_mvm
-- Generated on: 2026-05-08 22:35:07

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `transport_shipping_ecm`.`route` COMMENT 'SSOT for network topology, lane definitions, hub-and-spoke configurations, and transport route planning across all modes and geographies. Owns origin-destination lane master, service corridors, transit time standards, last-mile delivery zones, carrier lane allocations, ETA/ETD management, and network optimization outputs from Blue Yonder. Supports predictive ETA calculation, load optimization, carrier selection, and FourKites real-time visibility integration.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `transport_shipping_ecm`.`route`.`lane` (
    `lane_id` BIGINT COMMENT 'Unique surrogate identifier for the origin-destination lane record. Primary key used across SAP TM, Oracle TMS, and Blue Yonder for rate lookup, carrier selection, and network optimization.',
    `agreement_id` BIGINT COMMENT 'Reference to the carrier or customer contract governing rates, SLAs, and operational terms for this lane. Links to the Contract and Agreement domain for rate lookup and charge calculation in SAP TM.',
    `carrier_id` BIGINT COMMENT 'Reference to the primary contracted carrier allocated to this lane for standard shipment execution. Used by SAP TM carrier selection engine and Oracle TMS for freight audit and load optimization.',
    `carrier_service_id` BIGINT COMMENT 'Foreign key linking to network.carrier_service. Business justification: Lanes are often contracted under specific carrier service products with defined service levels. Required for rate application during quoting, service-level routing decisions, and contracted service va',
    `network_node_id` BIGINT COMMENT 'Reference to the destination network node (city, port, airport, ICD, CFS, or postal zone) at which this lane terminates. Paired with origin_location_id to define the directional transport corridor.',
    `lane_network_node_id` BIGINT COMMENT 'Reference to the origin network node (city, port, airport, Inland Container Depot (ICD), Container Freight Station (CFS), or postal zone) from which this lane departs. Drives carrier selection and rate lookup in SAP TM.',
    `aeo_required` BOOLEAN COMMENT 'Indicates whether Authorized Economic Operator (AEO) certification is required for carriers or shippers operating on this lane. Enforced during carrier selection in SAP TM and compliance screening in Descartes Customs.',
    `blue_yonder_lane_code` STRING COMMENT 'External lane identifier assigned by Blue Yonder Supply Chain Planning system for network optimization, demand forecasting, and inventory optimization workflows. Used for cross-system reconciliation between the lakehouse and Blue Yonder.',
    `co2e_emission_factor` DECIMAL(18,2) COMMENT 'Greenhouse Gas (GHG) emission factor in kilograms of Carbon Dioxide Equivalent (CO2e) per tonne-kilometre for this lane and transport mode. Used for sustainability reporting under EU ETS, CORSIA, and GHG Protocol Scope 3 calculations.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this lane record was first created in the system of record and ingested into the Silver Layer. Supports data lineage, audit trail, and SOX compliance for master data change management.',
    `destination_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the lane destination. Used for cross-border compliance, Importer Security Filing (ISF), and Automated Manifest System (AMS) reporting.. Valid values are `^[A-Z]{3}$`',
    `destination_unlocode` STRING COMMENT 'United Nations Code for Trade and Transport Locations (UN/LOCODE) for the lane destination node. Used in EDI messages, Air Waybill (AWB), Master Bill of Lading (MBL), and Automated Manifest System (AMS) filings.. Valid values are `^[A-Z]{2}[A-Z0-9]{3}$`',
    `distance_km` DECIMAL(18,2) COMMENT 'Physical distance of the lane corridor in kilometres. Used for freight rate calculation, Dimensional Weight (DIM Weight) pricing, Carbon Dioxide Equivalent (CO2e) emissions estimation, and network optimization in Blue Yonder.',
    `distance_miles` DECIMAL(18,2) COMMENT 'Physical distance of the lane corridor in miles. Maintained alongside distance_km to support US DOT regulatory reporting and North American carrier rate negotiations where miles are the contractual unit.',
    `edi_lane_code` STRING COMMENT 'Lane identifier used in Electronic Data Interchange (EDI) messages exchanged with carriers, customs authorities, and trading partners. May differ from internal lane_code due to carrier-specific EDI mapping requirements.',
    `effective_from` DATE COMMENT 'Date from which this lane definition becomes operationally active and available for shipment booking, carrier selection, and rate lookup. Supports temporal lane versioning in SAP TM and Blue Yonder.',
    `effective_until` DATE COMMENT 'Date on which this lane definition expires and is no longer available for new bookings. Null indicates an open-ended lane with no planned expiry. Used for lane lifecycle management and network re-optimization in Blue Yonder.',
    `frequency_per_week` STRING COMMENT 'Number of scheduled departures per week on this lane. Used for capacity planning, shipment booking availability, and On-Time In-Full (OTIF) performance management. Sourced from carrier schedules in SAP TM.',
    `ftz_applicable` BOOLEAN COMMENT 'Indicates whether this lane passes through or terminates in a Free Trade Zone (FTZ), enabling duty deferral, bonded warehouse processing, or re-export without full customs clearance. Managed in Descartes Customs.',
    `incoterms_code` STRING COMMENT 'Applicable International Commercial Terms (Incoterms) governing risk and cost transfer on this lane. Determines customs brokerage responsibilities, insurance requirements, and freight charge allocation. Aligned with ICC Incoterms 2020. [ENUM-REF-CANDIDATE: EXW|FCA|CPT|CIP|DAP|DPU|DDP|FAS|FOB|CFR|CIF — 11 candidates stripped; promote to reference product]',
    `is_capacity_freeze` BOOLEAN COMMENT 'Indicates whether capacity on this lane is frozen, preventing new load optimization allocations. Set by Blue Yonder during peak season planning or carrier capacity constraint events. Synchronized to Oracle TMS for load optimization.',
    `is_cross_border` BOOLEAN COMMENT 'Indicates whether this lane crosses an international border, triggering customs brokerage, Importer Security Filing (ISF), and trade compliance workflows in Descartes Customs. True for international lanes; False for domestic.',
    `is_dg_permitted` BOOLEAN COMMENT 'Indicates whether Dangerous Goods (DG) shipments are permitted on this lane. False triggers a DG prohibition restriction. Governed by IMDG Code for ocean, ICAO Technical Instructions for air, and ADR for road transport.',
    `is_embargo_active` BOOLEAN COMMENT 'Indicates whether a trade or operational embargo is currently active on this lane, blocking new shipment bookings. Embargo status is managed in Descartes Customs and synchronized to SAP TM for carrier selection exclusion.',
    `is_seasonal_closure` BOOLEAN COMMENT 'Indicates whether this lane is subject to a seasonal closure (e.g., weather-related road closures, monsoon port restrictions). When True, the lane is excluded from carrier selection and route planning during the closure window.',
    `lane_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the lane, used in SAP TM and Oracle TMS for rate lookup, freight order management, and carrier selection. Serves as the canonical cross-system reference key.. Valid values are `^[A-Z0-9]{3,20}$`',
    `lane_name` STRING COMMENT 'Human-readable descriptive name for the lane, typically formatted as origin-destination pair (e.g., Shanghai Port – Los Angeles Port Ocean FCL). Used in reporting, carrier communications, and network planning dashboards.',
    `lane_status` STRING COMMENT 'Current operational lifecycle status of the lane. Active lanes are available for shipment booking and carrier allocation. Suspended lanes are temporarily unavailable. Under_review lanes are pending network optimization assessment in Blue Yonder.. Valid values are `active|inactive|suspended|under_review`',
    `lane_tier` STRING COMMENT 'Strategic tier classification of the lane based on volume, revenue contribution, and network criticality. Tier 1 lanes are high-volume strategic corridors; Tier 3 are low-frequency secondary lanes. Used by Blue Yonder for network optimization prioritization.. Valid values are `tier_1|tier_2|tier_3|strategic`',
    `lane_type` STRING COMMENT 'Classification of the lane by service category: express (time-definite premium), freight (standard bulk), last_mile (final delivery segment), cross_border (international), domestic (within-country), or multimodal (multiple transport modes). Drives SLA assignment and pricing tier in SAP TM. [ENUM-REF-CANDIDATE: express|freight|last_mile|cross_border|domestic|multimodal — promote to reference product]. Valid values are `express|freight|last_mile|cross_border|domestic|multimodal`',
    `last_mile_zone_code` STRING COMMENT 'Delivery zone code for last-mile operations at the destination, used for postal zone routing, delivery slot assignment, and Door-to-Door (D2D) service configuration. Applicable when lane_type is last_mile.',
    `max_volume_cbm` DECIMAL(18,2) COMMENT 'Maximum allowable shipment volume in Cubic Metres (CBM) for a single consignment on this lane. Used alongside Dimensional Weight (DIM Weight) calculations for air freight rating and ocean FCL/LCL capacity planning.',
    `max_weight_kg` DECIMAL(18,2) COMMENT 'Maximum allowable gross shipment weight in kilograms for a single consignment on this lane. Enforced during load optimization in Oracle TMS and freight order management in SAP TM. Derived from carrier and infrastructure constraints.',
    `network_region` STRING COMMENT 'Geographic network region grouping for this lane (e.g., Asia-Pacific, Europe, Americas, Middle East Africa). Used for network planning, capacity management, and regional P&L reporting in SAP S/4HANA Finance.',
    `origin_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the lane origin. Used for customs compliance, trade restriction screening, and regulatory reporting to WCO and Descartes Customs.. Valid values are `^[A-Z]{3}$`',
    `origin_unlocode` STRING COMMENT 'United Nations Code for Trade and Transport Locations (UN/LOCODE) for the lane origin node. Five-character code used in EDI (Electronic Data Interchange) messages, customs declarations, and Bill of Lading (BOL) documentation.. Valid values are `^[A-Z]{2}[A-Z0-9]{3}$`',
    `remarks` STRING COMMENT 'Free-text operational notes or remarks about this lane, capturing special handling instructions, carrier-specific requirements, or network planning context not captured in structured fields. Used by operations and network planning teams.',
    `restriction_authority` STRING COMMENT 'Name of the regulatory body or internal authority that imposed the current lane restriction (e.g., IMO, IATA, US DOT, WCO, Internal Network Operations). Required for compliance audit and regulatory reporting.',
    `restriction_effective_from` DATE COMMENT 'Date from which the current operational restriction on this lane becomes effective. Used by SAP TM to exclude the lane from carrier selection and by Descartes Customs for trade compliance enforcement.',
    `restriction_effective_until` DATE COMMENT 'Date on which the current operational restriction on this lane expires and normal operations resume. Null indicates an indefinite restriction. Monitored by Blue Yonder for network re-optimization upon restriction lift.',
    `restriction_type` STRING COMMENT 'Categorical type of the most recently applied operational restriction on this lane. Used for exception reporting and compliance audit trails. Detailed restriction history is maintained in the lane_restriction event log.. Valid values are `embargo|dg_prohibition|seasonal_closure|capacity_freeze|regulatory_hold`',
    `sap_tm_lane_code` STRING COMMENT 'External lane identifier from SAP TM (Transportation Management) used for route planning, freight order management, charge calculation, and carrier selection. Enables bidirectional synchronization between the Silver Layer and SAP TM.',
    `standard_transit_days` STRING COMMENT 'Contractual standard transit time in calendar days from origin pickup to destination delivery for this lane. Used as the baseline for SLA compliance measurement, On-Time Delivery (OTD) KPI calculation, and Estimated Time of Arrival (ETA) computation in FourKites.',
    `transport_mode` STRING COMMENT 'Primary mode of transport for this lane: air (IATA-governed), ocean (IMO-governed), road (DOT-governed), rail, or multimodal (combination). Determines applicable regulatory framework, carrier pool, and rate structure in Oracle TMS.. Valid values are `air|ocean|road|rail|multimodal`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this lane record. Used for incremental data pipeline processing, change data capture, and audit trail maintenance in the Databricks Silver Layer.',
    `visibility_tracking_enabled` BOOLEAN COMMENT 'Indicates whether FourKites real-time GPS/IoT shipment tracking and predictive ETA calculation is enabled for shipments on this lane. Drives exception management and proactive customer notification workflows.',
    CONSTRAINT pk_lane PRIMARY KEY(`lane_id`)
) COMMENT 'Master origin-destination lane definition representing a directional transport corridor between two network nodes (city, port, airport, ICD, CFS, or postal zone pair). Owns the canonical lane identifier used across SAP TM, Oracle TMS, and Blue Yonder for rate lookup, carrier selection, and network optimization. Captures lane type (express, freight, last-mile), transport mode (air, ocean, road, rail, multimodal), lane status, standard transit time, distance (km/miles), lane tier classification, applicable Incoterms, operational restrictions (embargo, DG prohibition, seasonal closure, capacity freeze), restriction effective dates, and restriction authority. SSOT for all O-D lane master data referenced by pricing, freight, and shipment domains.';

CREATE OR REPLACE TABLE `transport_shipping_ecm`.`route`.`network_node` (
    `network_node_id` BIGINT COMMENT 'Unique surrogate identifier for each physical or logical node in the transport network. Primary key for the network_node master record.',
    `partner_id` BIGINT COMMENT 'Foreign key linking to network.network_partner. Business justification: Many terminals, warehouses, and cross-docks are operated by third-party partners. Required for partner performance tracking, operational coordination, cost allocation, and partner SLA compliance monit',
    `address_line1` STRING COMMENT 'Primary street address of the network node facility. Used for carrier pickup/delivery instructions, customs documentation in Descartes, and last-mile routing in Oracle TMS.',
    `aeo_certified` BOOLEAN COMMENT 'Indicates whether the node or its operating entity holds Authorized Economic Operator (AEO) certification, enabling expedited customs clearance and reduced inspections. True = AEO certified. Used in Descartes Customs for trade lane compliance scoring.',
    `blue_yonder_node_code` STRING COMMENT 'Node identifier as defined in Blue Yonder Supply Chain Planning for network design, demand forecasting, and inventory optimization models. Used to synchronize network topology between the lakehouse silver layer and Blue Yonder planning outputs.',
    `city_name` STRING COMMENT 'Name of the city or municipality where the network node is located. Used for geographic display in shipment tracking, carrier selection, and last-mile delivery zone mapping.',
    `co2e_emission_factor` DECIMAL(18,2) COMMENT 'Node-level Carbon Dioxide Equivalent (CO2e) emission factor in kg CO2e per CBM processed, used for Greenhouse Gas (GHG) footprint calculation in sustainability reporting. Supports EU Emissions Trading System (EU ETS) and CORSIA compliance reporting.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 three-letter country code of the country where the node is physically located (e.g., HKG, SGP, USA). Used for customs compliance routing in Descartes, trade lane classification, and regulatory reporting.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this network node record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Provides audit trail for data lineage and SOX compliance.',
    `ctpat_certified` BOOLEAN COMMENT 'Indicates whether the node is C-TPAT certified, confirming compliance with US Customs and Border Protection supply chain security standards. True = C-TPAT certified. Required for US-bound shipment routing and ISF filing in Descartes.',
    `customs_bonded` BOOLEAN COMMENT 'Indicates whether the node operates as a customs bonded warehouse or zone, allowing storage of goods under customs control without duty payment until release. True = bonded facility. Used in Descartes Customs for trade compliance routing and ISF/AMS filing.',
    `dg_handling_enabled` BOOLEAN COMMENT 'Indicates whether the node is certified and equipped to handle Dangerous Goods (DG) shipments. True = DG-certified facility. Used in SAP TM carrier and route selection to ensure DG shipments are only routed through compliant nodes per IMDG Code and ICAO Technical Instructions.',
    `effective_from` DATE COMMENT 'Date from which this network node record is valid and the node is available for route planning and shipment assignment. Used for temporal validity management in SAP TM and Blue Yonder network versioning.',
    `effective_until` DATE COMMENT 'Date after which this network node record is no longer valid. Null indicates the node is open-ended with no planned end date. Used for network topology versioning, decommissioning planning, and historical route analysis.',
    `folio_visibility_code` STRING COMMENT 'Location identifier assigned to this node in the FourKites Real-Time Visibility Platform. Used to correlate network node records with live shipment tracking events, predictive ETA calculations, and exception alerts from FourKites.',
    `ftz_designation` BOOLEAN COMMENT 'Indicates whether the node is located within or operates as a Free Trade Zone (FTZ), enabling duty-free handling and value-added services. True = FTZ-designated node. Used for trade compliance routing in Descartes and DDP/DAP Incoterms processing.',
    `handling_capacity_cbm` DECIMAL(18,2) COMMENT 'Maximum volumetric throughput capacity of the node measured in Cubic Meters (CBM) per day. Used for load optimization in Oracle TMS, capacity planning in Blue Yonder, and network bottleneck analysis.',
    `hub_tier` STRING COMMENT 'Hierarchical tier of the node within the hub-and-spoke network topology. primary = global mega-hub (e.g., main international gateway); secondary = regional hub; tertiary = country-level distribution center; spoke = local delivery depot. Drives routing hierarchy in SAP TM and Blue Yonder network design.. Valid values are `primary|secondary|tertiary|spoke`',
    `iata_code` STRING COMMENT 'Three-letter IATA airport or city code assigned to the node where applicable (e.g., HKG, SIN, LHR). Used for air freight routing, House Air Waybill (HAWB) and Master Air Waybill (MAWB) origin/destination coding, and IATA-compliant carrier communications. Null for non-air nodes.. Valid values are `^[A-Z]{3}$`',
    `icao_airport_code` STRING COMMENT 'Four-letter ICAO airport designator for air cargo terminal nodes (e.g., VHHH for Hong Kong International). Used for air freight routing, MAWB/HAWB coding, and ICAO regulatory compliance. Null for non-airport nodes.. Valid values are `^[A-Z]{4}$`',
    `imo_port_code` STRING COMMENT 'Seven-digit IMO port facility code assigned to sea port nodes. Used for ocean freight Bill of Lading (BOL) routing, vessel manifest filing, and IMO regulatory compliance reporting. Null for non-port nodes.. Valid values are `^[0-9]{7}$`',
    `latitude` DECIMAL(18,2) COMMENT 'WGS-84 decimal latitude coordinate of the network node (e.g., 22.308901 for Hong Kong International Airport). Used for GPS-based distance calculations, FourKites real-time shipment proximity tracking, and Blue Yonder network design optimization.',
    `longitude` DECIMAL(18,2) COMMENT 'WGS-84 decimal longitude coordinate of the network node (e.g., 113.914603 for Hong Kong International Airport). Used in conjunction with latitude for geospatial route planning, ETA calculation, and IoT-based asset tracking integration.',
    `max_weight_capacity_kg` DECIMAL(18,2) COMMENT 'Maximum gross weight in kilograms that the node can handle per shipment or per day (context defined by operational policy). Used for load optimization in Oracle TMS and freight order feasibility checks in SAP TM.',
    `node_code` STRING COMMENT 'Externally-known, human-readable unique business code assigned to the node (e.g., HKG-HUB-01, SIN-CFS-02). Used as the operational reference key in SAP TM route planning, Blue Yonder network design, and FourKites visibility integration.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `node_name` STRING COMMENT 'Full descriptive name of the network node (e.g., Hong Kong International Gateway Hub, Singapore Container Freight Station). Used in operational reports, carrier communications, and customer-facing shipment tracking.',
    `node_status` STRING COMMENT 'Current lifecycle status of the network node. Controls whether the node is available for route planning and shipment assignment in SAP TM and Oracle TMS. active = fully operational; inactive = temporarily not in use; suspended = operations halted pending review; under_construction = not yet operational; decommissioned = permanently retired from the network.. Valid values are `active|inactive|suspended|under_construction|decommissioned`',
    `node_type` STRING COMMENT 'Classification of the node by its operational role in the transport network. Drives hub-and-spoke topology logic in SAP TM and Blue Yonder. Values: hub (major consolidation/distribution center), gateway (international entry/exit point), sorting_center (parcel sorting facility), warehouse (storage and fulfillment), port (sea port terminal), airport (air cargo terminal), icd (Inland Container Depot), cfs (Container Freight Station), ftz (Free Trade Zone), last_mile_depot (final delivery depot). [ENUM-REF-CANDIDATE: hub|gateway|sorting_center|warehouse|port|airport|icd|cfs|ftz|last_mile_depot — promote to reference product]',
    `operating_days` STRING COMMENT 'Comma-separated list of operating days using ISO weekday abbreviations (e.g., MON,TUE,WED,THU,FRI or MON,TUE,WED,THU,FRI,SAT). Used for freight scheduling, carrier dispatch planning, and SLA transit time calculation in SAP TM.',
    `operating_hours_end` STRING COMMENT 'Local time at which the node ceases operations each day in HH:MM 24-hour format (e.g., 22:00). Used by SAP TM for cut-off time enforcement, freight order scheduling, and SLA breach risk assessment.. Valid values are `^([01]d|2[0-3]):[0-5]d$`',
    `operating_hours_start` STRING COMMENT 'Local time at which the node begins operations each day in HH:MM 24-hour format (e.g., 06:00). Used by SAP TM for freight order scheduling, carrier appointment booking, and last-mile delivery window planning.. Valid values are `^([01]d|2[0-3]):[0-5]d$`',
    `oversized_cargo_enabled` BOOLEAN COMMENT 'Indicates whether the node has the equipment and infrastructure to handle oversized or out-of-gauge cargo (e.g., heavy lift cranes, wide-load bays). True = oversized cargo capable. Used in SAP TM special cargo routing.',
    `parent_node_code` STRING COMMENT 'Node code of the parent node in the hub-and-spoke hierarchy (e.g., a spoke depots parent is its regional hub). Enables hierarchical network topology traversal for route planning and network performance roll-up reporting. Self-referencing relationship resolved in the linking step.',
    `postal_code` STRING COMMENT 'Postal or ZIP code of the network node facility address. Used for last-mile delivery zone assignment, carrier rate lookup, and geographic clustering in Blue Yonder network optimization.',
    `region_code` STRING COMMENT 'Internal geographic region code grouping the node into a commercial or operational region (e.g., APAC, EMEA, AMER, MEA). Used for network performance reporting, regional P&L allocation in SAP S/4HANA Finance, and Blue Yonder network design segmentation.. Valid values are `^[A-Z]{2,10}$`',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this network node record was sourced (e.g., SAP_TM, BLUE_YONDER). Used for data lineage tracking, reconciliation, and master data management governance in the Databricks lakehouse.. Valid values are `SAP_TM|ORACLE_TMS|BLUE_YONDER|MANHATTAN_WMS|MANUAL`',
    `storage_capacity_cbm` DECIMAL(18,2) COMMENT 'Maximum static storage capacity of the node measured in Cubic Meters (CBM). Used for warehouse capacity planning in Manhattan WMS, inventory optimization in Blue Yonder, and network design decisions.',
    `temp_range_max_celsius` DECIMAL(18,2) COMMENT 'Maximum temperature in degrees Celsius that the nodes temperature-controlled facility can maintain (e.g., 8.00 for refrigerated). Null if temperature_controlled is False. Used for cold-chain shipment routing and cargo integrity compliance.',
    `temp_range_min_celsius` DECIMAL(18,2) COMMENT 'Minimum temperature in degrees Celsius that the nodes temperature-controlled facility can maintain (e.g., -25.00 for deep freeze). Null if temperature_controlled is False. Used for cold-chain shipment routing and SLA compliance validation.',
    `temperature_controlled` BOOLEAN COMMENT 'Indicates whether the node has temperature-controlled storage and handling capabilities (cold chain). True = facility supports temperature-sensitive cargo. Used for pharmaceutical, perishable, and cold-chain shipment routing in SAP TM.',
    `teu_capacity` STRING COMMENT 'Maximum container throughput capacity of the node measured in Twenty-foot Equivalent Units (TEU) per day. Applicable to port, ICD, CFS, and FTZ nodes. Used for ocean freight capacity planning and FCL/LCL load optimization in Oracle TMS.',
    `timezone_code` STRING COMMENT 'IANA time zone identifier for the nodes local time zone (e.g., Asia/Hong_Kong, America/New_York, Europe/London). Critical for accurate ETD/ETA calculation, operating hours enforcement in SAP TM, and SLA compliance measurement across time zones.',
    `tms_location_code` STRING COMMENT 'Location identifier code as registered in SAP TM and Oracle TMS for route planning, freight order management, and carrier selection. Serves as the cross-system reference key for transport execution systems.',
    `transport_mode` STRING COMMENT 'Primary transport mode served by this network node. Determines applicable regulatory frameworks (IATA for air, IMO for ocean, DOT for road/rail) and routing logic in SAP TM. multimodal indicates the node serves multiple modes (e.g., an intermodal terminal).. Valid values are `air|ocean|road|rail|multimodal`',
    `un_locode` STRING COMMENT 'Five-character UN/LOCODE identifying the geographic location of the node (e.g., HKHKG, SGSIN). Used for Bill of Lading (BOL), customs declarations in Descartes, and EDI messaging per WCO standards. Provides a globally standardized location reference across all transport modes.. Valid values are `^[A-Z]{2}[A-Z0-9]{3}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this network node record was last modified, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for change data capture (CDC) in the Databricks lakehouse silver layer and audit trail maintenance.',
    `wms_facility_code` STRING COMMENT 'Facility identifier code as registered in Manhattan WMS for nodes that perform warehousing and fulfillment operations. Used to link network node records to WMS inventory, labor, and slotting data. Null for non-warehouse nodes.',
    CONSTRAINT pk_network_node PRIMARY KEY(`network_node_id`)
) COMMENT 'Master record for every physical or logical node in the transport network including origin/destination hubs, gateways, sorting centers, warehouses, ICDs, CFSs, FTZs, ports, airports, and last-mile delivery depots. Captures node code, node type, IATA/UN LOCODE, geographic coordinates (lat/long), country, region, time zone, operating hours, handling capabilities (dangerous goods, temperature-controlled, oversized), and node status. Serves as the geographic backbone for hub-and-spoke topology and route planning in SAP TM and Blue Yonder.';

CREATE OR REPLACE TABLE `transport_shipping_ecm`.`route`.`service_corridor` (
    `service_corridor_id` BIGINT COMMENT 'Unique surrogate identifier for the service corridor record. Primary key for the service_corridor data product within the route domain.',
    `network_node_id` BIGINT COMMENT 'Foreign key linking to route.network_node. Business justification: service_corridor defines a named multi-leg corridor connecting network nodes. The origin_hub_code STRING field is a denormalized reference to the origin network node. Adding origin_network_node_id as ',
    `trade_agreement_id` BIGINT COMMENT 'Foreign key linking to customs.trade_agreement. Business justification: Service corridor planning incorporates trade agreement zones for network optimization. Corridors designed to leverage FTA benefits (e.g., USMCA-compliant routing through Mexico) require explicit agree',
    `awb_prefix` STRING COMMENT 'Three-digit IATA Air Waybill (AWB) prefix assigned to the primary carrier operating this air corridor. Applicable only for AIR transport mode corridors. Used for MAWB (Master Air Waybill) and HAWB (House Air Waybill) number generation in SAP TM.. Valid values are `^[0-9]{3}$`',
    `capacity_teu` DECIMAL(18,2) COMMENT 'Weekly or per-departure capacity of this corridor expressed in Twenty-foot Equivalent Units (TEU) for ocean corridors, or equivalent volumetric capacity for other modes. Used in Blue Yonder capacity planning and SAP TM load optimization.',
    `carrier_scac_codes` STRING COMMENT 'Comma-separated list of Standard Carrier Alpha Codes (SCAC) or IATA carrier codes for carriers allocated to operate on this corridor. Used in SAP TM carrier selection and Oracle TMS freight audit. Supports multi-carrier corridor configurations.',
    `co2e_emission_factor` DECIMAL(18,2) COMMENT 'Carbon Dioxide Equivalent (CO2e) emission factor in kg CO2e per tonne-kilometre for this corridor, based on transport mode and carrier mix. Used for GHG (Greenhouse Gas) emissions reporting, EU ETS compliance, CORSIA carbon offsetting calculations, and sustainability KPI dashboards.',
    `corridor_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the service corridor, used in SAP TM route planning and Blue Yonder network design (e.g., APAC-AIR-EXP-01, TPAC-OCN-FCL-02). Referenced in EDI messages and carrier lane allocations.. Valid values are `^[A-Z0-9-]{3,30}$`',
    `corridor_name` STRING COMMENT 'Human-readable name of the service corridor describing the route path and service product (e.g., Express Air Asia-Pacific, Ocean FCL Trans-Pacific, Road FTL Europe Central). Used in operational dashboards, carrier communications, and Blue Yonder network design outputs.',
    `corridor_status` STRING COMMENT 'Current operational lifecycle status of the service corridor. ACTIVE corridors are available for shipment routing in SAP TM. SUSPENDED corridors are temporarily unavailable (e.g., due to port congestion, regulatory hold). PLANNED corridors are in network design phase in Blue Yonder. DISCONTINUED corridors are archived.. Valid values are `ACTIVE|INACTIVE|SUSPENDED|PLANNED|DISCONTINUED`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this service corridor record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Audit trail field for data governance, SOX compliance, and lineage tracking in the Databricks Silver Layer.',
    `customs_clearance_required` BOOLEAN COMMENT 'Indicates whether customs clearance is required for shipments transiting this corridor. TRUE for cross-border corridors requiring Descartes Customs processing, ISF filing, and AMS submission. FALSE for domestic or intra-customs-union corridors (e.g., intra-EU).',
    `dangerous_goods_permitted` BOOLEAN COMMENT 'Indicates whether dangerous goods (DG) shipments are permitted on this corridor. Governed by IMDG Code for ocean, ICAO Technical Instructions for air, and ADR for road. Drives carrier selection and compliance checks in SAP TM and Descartes Customs.',
    `destination_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the corridors destination country (e.g., GBR, AUS, BRA). Used for customs compliance in Descartes, trade lane reporting, and cross-border regulatory requirements under WCO and WTO frameworks.. Valid values are `^[A-Z]{3}$`',
    `destination_hub_code` STRING COMMENT 'IATA airport code or UN/LOCODE of the primary destination hub node for this corridor (e.g., LHR for London Heathrow, USLAX for Los Angeles). Anchors the corridors terminal network node in SAP TM route planning and FourKites real-time visibility.. Valid values are `^[A-Z]{3,5}$`',
    `destination_region` STRING COMMENT 'Named geographic region where the service corridor terminates (e.g., Europe, Middle East, Latin America). Used for network topology grouping, lane allocation, and Blue Yonder network design. Distinct from specific destination node.',
    `direction_type` STRING COMMENT 'Indicates whether the corridor is defined for outbound (origin to destination), inbound (destination to origin), or bilateral (both directions) traffic flow. Drives lane allocation and backhaul optimization in SAP TM and Oracle TMS.. Valid values are `OUTBOUND|INBOUND|BILATERAL`',
    `distance_km` DECIMAL(18,2) COMMENT 'Total great-circle or road/rail network distance in kilometres for the full corridor from origin hub to destination hub including all intermediate legs. Used for CO2e emissions calculation, freight rate benchmarking, and Blue Yonder network optimization.',
    `edi_enabled` BOOLEAN COMMENT 'Indicates whether Electronic Data Interchange (EDI) messaging is enabled for carrier communications on this corridor (e.g., EDI 214 shipment status, EDI 210 freight invoice). Drives automated data exchange configuration in SAP TM and Oracle TMS freight audit.',
    `effective_date` DATE COMMENT 'Date from which this service corridor becomes operationally active and available for shipment routing in SAP TM. Used for corridor lifecycle management, seasonal schedule changes, and network design transitions.',
    `expiry_date` DATE COMMENT 'Date on which this service corridor ceases to be operationally active. NULL indicates an open-ended corridor with no planned end date. Used for corridor lifecycle management and seasonal schedule deactivation in SAP TM.',
    `freight_product` STRING COMMENT 'Specific freight product type carried on this corridor. FCL (Full Container Load), LCL (Less than Container Load), FTL (Full Truckload), LTL (Less than Truckload), AIR_FREIGHT, PARCEL, BULK, or BREAKBULK. Governs load optimization rules in Oracle TMS and capacity planning in Blue Yonder. [ENUM-REF-CANDIDATE: FCL|LCL|FTL|LTL|AIR_FREIGHT|PARCEL|BULK|BREAKBULK — promote to reference product]',
    `frequency_days_of_week` STRING COMMENT 'Comma-separated list of days on which the corridor operates (e.g., MON,WED,FRI for tri-weekly ocean service, MON,TUE,WED,THU,FRI,SAT,SUN for daily express). Used in SAP TM departure scheduling and customer-facing ETD commitments.',
    `frequency_type` STRING COMMENT 'Operational frequency at which the service corridor runs (e.g., DAILY for express parcel, WEEKLY for ocean FCL). Drives departure schedule planning in SAP TM, capacity allocation in Blue Yonder, and ETD/ETA commitments communicated to customers.. Valid values are `DAILY|WEEKLY|BI_WEEKLY|MONTHLY|ON_DEMAND`',
    `hub_spoke_role` STRING COMMENT 'Classification of this corridors role within the hub-and-spoke network topology. HUB_TO_HUB for main trunk routes, HUB_TO_SPOKE for distribution legs, SPOKE_TO_HUB for collection legs, SPOKE_TO_SPOKE for direct point-to-point routes. Used in Blue Yonder network design and SAP TM route planning.. Valid values are `HUB_TO_HUB|HUB_TO_SPOKE|SPOKE_TO_HUB|SPOKE_TO_SPOKE`',
    `incoterms_applicability` STRING COMMENT 'Comma-separated list of Incoterms (International Commercial Terms) applicable to shipments on this corridor (e.g., FOB,CIF,DDP,DAP,EXW). Governs risk transfer and cost responsibility rules for cross-border shipments. Aligned with ICC Incoterms 2020 and WTO trade facilitation requirements.',
    `intermediate_hub_sequence` STRING COMMENT 'Ordered, pipe-delimited sequence of intermediate hub codes (IATA or UN/LOCODE) traversed between origin and destination (e.g., DXB|FRA for Dubai then Frankfurt). Defines the multi-node path that distinguishes a corridor from a single O-D lane. Consumed by SAP TM for multi-leg route planning.',
    `last_mile_included` BOOLEAN COMMENT 'Indicates whether last-mile delivery to the final consignee is included within this corridors scope. TRUE for D2D (Door-to-Door) corridors. FALSE for port-to-port or hub-to-hub corridors where last-mile is handled separately.',
    `leg_count` STRING COMMENT 'Total number of transport legs in this service corridor, including origin-to-first-hub, all intermediate legs, and final leg to destination. Derived from the hub sequence but stored for query performance in SAP TM load optimization and Blue Yonder network design.',
    `max_volume_cbm` DECIMAL(18,2) COMMENT 'Maximum volumetric capacity in Cubic Meters (CBM) per shipment or per departure on this corridor. Used alongside DIM Weight (Dimensional Weight) calculations for air freight rating and load optimization in Oracle TMS and SAP TM charge calculation.',
    `max_weight_kg` DECIMAL(18,2) COMMENT 'Maximum gross weight in kilograms permitted per shipment on this corridor, based on carrier capacity constraints, regulatory limits, and infrastructure limitations (e.g., bridge weight limits for road, aircraft payload for air). Used in load optimization in Oracle TMS.',
    `network_design_code` BIGINT COMMENT 'Reference to the Blue Yonder network design scenario that generated or last optimized this corridor configuration. Enables traceability between network optimization outputs and operational corridor definitions.',
    `origin_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the corridors origin country (e.g., CHN, USA, DEU). Used for customs compliance in Descartes, trade lane reporting, and cross-border regulatory requirements under WCO and WTO frameworks.. Valid values are `^[A-Z]{3}$`',
    `origin_region` STRING COMMENT 'Named geographic region where the service corridor originates (e.g., Asia-Pacific, North America, Europe). Used for network topology grouping, lane allocation, and Blue Yonder network design. Distinct from specific origin node — this is the macro-geographic classification.',
    `primary_carrier_code` STRING COMMENT 'SCAC or IATA code of the primary/preferred carrier for this corridor. Used as the default carrier in SAP TM carrier selection logic. Distinct from carrier_scac_codes which lists all allocated carriers.. Valid values are `^[A-Z0-9]{2,4}$`',
    `priority_rank` STRING COMMENT 'Numeric priority ranking of this corridor relative to alternative corridors for the same O-D pair. Lower values indicate higher priority in SAP TM carrier selection and load optimization. Used when multiple corridors serve the same origin-destination combination.',
    `service_level_code` STRING COMMENT 'Internal SLA (Service Level Agreement) code that maps this corridor to a defined service level tier (e.g., P1-NEXT-DAY, P2-2DAY, STD-5DAY). Links to SLA entitlement definitions in Salesforce CRM and drives OTD/OTIF KPI measurement.. Valid values are `^[A-Z0-9-]{2,20}$`',
    `service_type` STRING COMMENT 'Classification of the service product offered on this corridor (e.g., EXPRESS for time-definite delivery, STANDARD for deferred, ECONOMY for cost-optimized). Determines SLA commitments, pricing tiers, and priority handling rules in SAP TM and Oracle TMS.. Valid values are `EXPRESS|STANDARD|ECONOMY|CHARTER|CONSOLIDATED`',
    `standard_transit_days` STRING COMMENT 'Standard total transit time in calendar days from origin pickup to destination delivery for this corridor under normal operating conditions. Used as the baseline for SLA commitments, ETA calculation in FourKites, and OTD (On-Time Delivery) KPI measurement.',
    `standard_transit_hours` STRING COMMENT 'Standard total transit time expressed in hours for sub-day precision, particularly relevant for express air corridors where transit is measured in hours rather than days (e.g., 18 hours for an overnight express air corridor). Complements standard_transit_days for precise ETA calculation.',
    `suspension_end_date` DATE COMMENT 'Expected or actual date on which a suspended corridor resumes operations. NULL if suspension end date is unknown. Used for proactive customer communication in Salesforce CRM and re-routing planning in SAP TM.',
    `suspension_reason` STRING COMMENT 'Reason code for corridor suspension. Used for exception reporting, root cause analysis, and regulatory compliance documentation. [ENUM-REF-CANDIDATE: PORT_CONGESTION|REGULATORY_EMBARGO|FORCE_MAJEURE|CARRIER_CAPACITY|INFRASTRUCTURE|SEASONAL|OTHER — promote to reference product]',
    `suspension_start_date` DATE COMMENT 'Date from which the corridor is temporarily suspended (e.g., due to port congestion, regulatory embargo, force majeure). Populated only when corridor_status is SUSPENDED. Used for exception management in FourKites and customer notification in Salesforce CRM.',
    `temperature_controlled` BOOLEAN COMMENT 'Indicates whether this corridor supports temperature-controlled (cold chain) shipments. Relevant for pharmaceutical, perishable food, and chemical cargo. Drives equipment type selection (reefer containers, temperature-controlled vehicles) in SAP TM and Oracle TMS.',
    `tracking_visibility_enabled` BOOLEAN COMMENT 'Indicates whether real-time shipment tracking and predictive ETA via FourKites is enabled for this corridor. TRUE enables GPS/IoT-based visibility, exception alerts, and predictive ETA updates for shipments on this corridor.',
    `transport_mode` STRING COMMENT 'Primary mode of transport for this service corridor. Drives carrier selection, regulatory compliance requirements, and charge calculation in SAP TM. Aligns with IATA (air), IMO (ocean), and DOT (road/rail) regulatory frameworks.. Valid values are `AIR|OCEAN|ROAD|RAIL|MULTIMODAL`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this service corridor record, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for change data capture (CDC) in the Databricks Silver Layer pipeline and audit trail compliance.',
    CONSTRAINT pk_service_corridor PRIMARY KEY(`service_corridor_id`)
) COMMENT 'Defines a named, multi-leg service corridor connecting a sequence of network nodes for a specific transport mode and service product (e.g., Express Air Asia-Pacific, Ocean FCL Trans-Pacific, Road FTL Europe). Captures corridor name, mode, service type, origin region, destination region, intermediate hub sequence, standard total transit time, frequency (daily/weekly), and operational status. Used by SAP TM for route planning and by Blue Yonder for network design optimization. Distinct from individual lanes — a corridor is a named multi-node path, a lane is a single O-D pair.';

CREATE OR REPLACE TABLE `transport_shipping_ecm`.`route`.`corridor_leg` (
    `corridor_leg_id` BIGINT COMMENT 'Unique surrogate identifier for each individual transport leg within a service corridor. Primary key for the corridor_leg entity in the Silver Layer lakehouse.',
    `carrier_id` BIGINT COMMENT 'Reference to the contracted carrier or transport operator assigned to execute this leg. Used for carrier lane allocation, freight audit, and carrier performance analytics in Oracle TMS.',
    `network_node_id` BIGINT COMMENT 'Reference to the network node (hub, port, airport, depot, ICD, CFS, or warehouse) where this leg terminates. Together with origin_node_id defines the origin-destination (OD) pair for this leg.',
    `lane_id` BIGINT COMMENT 'Foreign key linking to route.lane. Business justification: A corridor_leg represents a single node-to-node movement segment within a service corridor. A lane is the master origin-destination corridor definition for exactly that type of movement. Linking corri',
    `primary_corridor_network_node_id` BIGINT COMMENT 'Reference to the network node (hub, port, airport, depot, ICD, CFS, or warehouse) where this leg originates. Supports hub-and-spoke topology decomposition in SAP TM and Oracle TMS.',
    `service_corridor_id` BIGINT COMMENT 'Reference to the parent service corridor that this leg belongs to. A corridor is composed of one or more sequential legs representing the full origin-to-destination route.',
    `trade_agreement_id` BIGINT COMMENT 'Foreign key linking to customs.trade_agreement. Business justification: Corridor leg design must incorporate trade agreement rules (USMCA, EU FTAs) to enable preferential duty routing. Network planners configure legs to maintain origin qualification and minimize duty expo',
    `carrier_type` STRING COMMENT 'Classification of the carrier operating this leg. Determines applicable regulatory frameworks (IATA for airlines, IMO for ocean carriers, DOT for road), rate structures, and liability regimes. NVOCC applies to Non-Vessel Operating Common Carriers. [ENUM-REF-CANDIDATE: AIRLINE|OCEAN_CARRIER|ROAD_CARRIER|RAIL_OPERATOR|NVOCC|COURIER|INTERMODAL — promote to reference product]',
    `co2e_emission_factor` DECIMAL(18,2) COMMENT 'Carbon dioxide equivalent (CO2e) emission factor in kg per tonne-kilometre for this legs transport mode and vehicle type. Used to calculate shipment-level GHG emissions for EU ETS reporting, CORSIA compliance (air legs), and customer sustainability reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this corridor leg record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Provides audit trail for data lineage, SOX compliance, and Silver Layer ingestion tracking.',
    `cutoff_time` TIMESTAMP COMMENT 'Latest local time (HH:MM, 24-hour) by which freight must be tendered at the origin node to be accepted on this legs scheduled departure. Critical for shipment booking deadlines in Oracle TMS and customer SLA management.',
    `departure_days_mask` STRING COMMENT '7-character binary string (Mon=pos1 through Sun=pos7) indicating which days of the week this leg operates departures (1=operates, 0=does not operate). Enables precise booking calendar generation in SAP TM and Oracle TMS scheduling.. Valid values are `^[01]{7}$`',
    `departure_frequency` STRING COMMENT 'Frequency at which this leg operates departures. Drives shipment booking availability windows, capacity planning in Blue Yonder, and customer-facing transit time commitments. ON_DEMAND applies to charter and FTL legs.. Valid values are `DAILY|WEEKLY|BI_WEEKLY|TRI_WEEKLY|ON_DEMAND|SCHEDULED`',
    `destination_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the leg destination. Used for import/export compliance, denied party screening in Descartes, and bilateral trade lane reporting.. Valid values are `^[A-Z]{3}$`',
    `destination_location_code` STRING COMMENT 'Standardized location code for the leg destination — IATA airport code (3-letter) for air legs, UN/LOCODE (5-character) for ocean/road/rail legs. Used in AWB, BOL, and HAWB generation and customs declarations in Descartes.. Valid values are `^[A-Z]{3,5}$`',
    `distance_km` DECIMAL(18,2) COMMENT 'Physical distance of this transport leg in kilometres. Used for freight rate calculation (per-km tariffs), GHG/CO2e emissions estimation per EU ETS and CORSIA requirements, and network optimization in Blue Yonder.',
    `effective_from_date` DATE COMMENT 'Date from which this corridor leg definition becomes operationally valid and available for shipment assignment. Supports seasonal route activation, network redesign rollouts from Blue Yonder, and historical lane analytics.',
    `effective_to_date` DATE COMMENT 'Date after which this corridor leg definition is no longer operationally valid. Null indicates an open-ended lane with no planned expiry. Used for seasonal route deactivation, carrier contract expiry alignment, and network change management.',
    `fourtites_tracking_enabled` BOOLEAN COMMENT 'Indicates whether this leg is enrolled in FourKites real-time visibility tracking (True). When enabled, GPS/IoT telemetry is streamed for predictive ETA updates and exception management. Supports independent leg trackability as defined in the corridor_leg product scope.',
    `incoterms_applicability` STRING COMMENT 'International Commercial Terms (Incoterms) applicable to this leg, defining the point of risk and cost transfer between shipper and consignee. Governs liability allocation, insurance requirements, and customs filing responsibilities. [ENUM-REF-CANDIDATE: EXW|FCA|CPT|CIP|DAP|DPU|DDP|FAS|FOB|CFR|CIF — promote to reference product]',
    `is_cross_border` BOOLEAN COMMENT 'Indicates whether this leg crosses an international border (True) or is a domestic movement (False). Triggers customs declaration requirements in Descartes, ISF/AMS filing obligations, and AEO/C-TPAT compliance checks.',
    `is_dangerous_goods_permitted` BOOLEAN COMMENT 'Indicates whether this leg is certified and permitted to carry dangerous goods (True) or not (False). Governs shipment acceptance rules per IMDG Code for ocean legs and ICAO Technical Instructions for air legs.',
    `is_temperature_controlled` BOOLEAN COMMENT 'Indicates whether this leg provides temperature-controlled (cold chain) transport capability (True). Relevant for pharmaceutical, perishable, and high-value cargo routing and SLA compliance.',
    `last_reviewed_date` DATE COMMENT 'Date on which this corridor leg definition was last reviewed and validated by the network planning team. Supports data quality governance, periodic lane review cycles, and audit trail for network optimization decisions.',
    `leg_code` STRING COMMENT 'Externally-known alphanumeric business identifier for this corridor leg, used in SAP TM route planning, Oracle TMS load optimization, and EDI interchange with carriers. Unique within the parent corridor.. Valid values are `^[A-Z0-9]{3,20}$`',
    `leg_sequence_number` STRING COMMENT 'Ordinal position of this leg within the parent corridor, starting at 1. Defines the execution order for multi-modal route decomposition (e.g., leg 1 = road pickup, leg 2 = air haul, leg 3 = road delivery). Aligns with Oracle TMS load optimization sequencing.',
    `leg_status` STRING COMMENT 'Current operational lifecycle status of this corridor leg. ACTIVE legs are available for shipment assignment; SUSPENDED legs are temporarily unavailable; DISCONTINUED legs are retired from the network. Governs availability in Oracle TMS load optimization.. Valid values are `ACTIVE|INACTIVE|SUSPENDED|PLANNED|DISCONTINUED`',
    `load_type` STRING COMMENT 'Freight load configuration for this leg. FTL (Full Truckload), LTL (Less Than Truckload), FCL (Full Container Load), LCL (Less Than Container Load), PARCEL, BULK, or BREAK_BULK. Drives Oracle TMS load optimization, rate calculation, and capacity planning in Blue Yonder. [ENUM-REF-CANDIDATE: FTL|LTL|FCL|LCL|PARCEL|BULK|BREAK_BULK — promote to reference product]',
    `max_volume_capacity_cbm` DECIMAL(18,2) COMMENT 'Maximum volumetric capacity in Cubic Metres (CBM) available on this leg per departure. Used alongside max_weight_capacity_kg for DIM weight-based load optimization and capacity utilization analytics in Oracle TMS.',
    `max_weight_capacity_kg` DECIMAL(18,2) COMMENT 'Maximum chargeable or physical weight capacity in kilograms that this leg can accommodate per departure. Used for load optimization in Oracle TMS, capacity planning in Blue Yonder, and freight booking acceptance logic.',
    `origin_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the leg origin. Used for cross-border compliance checks, customs filing, AEO/C-TPAT screening, and trade lane analytics.. Valid values are `^[A-Z]{3}$`',
    `origin_location_code` STRING COMMENT 'Standardized location code for the leg origin — IATA airport code (3-letter) for air legs, UN/LOCODE (5-character) for ocean/road/rail legs. Used in AWB, BOL, and HAWB generation and AMS/ISF filings.. Valid values are `^[A-Z]{3,5}$`',
    `remarks` STRING COMMENT 'Free-text operational notes or remarks about this corridor leg, such as seasonal restrictions, port congestion advisories, special handling requirements, or network planning rationale. Intended for network planners and operations teams.',
    `service_type` STRING COMMENT 'Service level classification for this leg indicating speed and priority tier. Determines SLA commitments, rate applicability, and carrier selection logic in SAP TM charge calculation.. Valid values are `EXPRESS|STANDARD|ECONOMY|CHARTER|CONSOLIDATED`',
    `sla_on_time_threshold_hours` DECIMAL(18,2) COMMENT 'Maximum allowable transit time in hours for this leg before it is classified as a late delivery for OTD (On-Time Delivery) and OTIF (On-Time In-Full) KPI measurement. Sourced from contracted SLA terms and used in FourKites exception management.',
    `source_system_code` STRING COMMENT 'Identifies the operational system of record from which this corridor leg definition was sourced. SAP_TM for route planning lanes, ORACLE_TMS for shipment execution lanes, BLUE_YONDER for network optimization outputs, or MANUAL for analyst-entered lanes. Supports data lineage and master data governance.. Valid values are `SAP_TM|ORACLE_TMS|BLUE_YONDER|MANUAL`',
    `standard_arrival_time` TIMESTAMP COMMENT 'Standard local arrival time (HH:MM, 24-hour) at the destination node for this leg. Used as the baseline Estimated Time of Arrival (ETA) for downstream leg connections, delivery scheduling, and OTD/OTIF KPI measurement.',
    `standard_departure_time` TIMESTAMP COMMENT 'Standard local departure time (HH:MM, 24-hour) for this leg at the origin node. Used as the baseline Estimated Time of Departure (ETD) for shipment scheduling, FourKites tracking initialization, and customer notification triggers.',
    `standard_transit_hours` DECIMAL(18,2) COMMENT 'Contracted or standard transit time for this leg expressed in decimal hours. Used as the baseline for ETA calculation, SLA commitment derivation, and predictive ETA modeling in FourKites. Sourced from SAP TM transit time matrix.',
    `temperature_max_celsius` DECIMAL(18,2) COMMENT 'Maximum temperature in degrees Celsius maintained during transport on this leg. Applicable only when is_temperature_controlled is True. Used for cold chain compliance validation and cargo acceptance rules.',
    `temperature_min_celsius` DECIMAL(18,2) COMMENT 'Minimum temperature in degrees Celsius maintained during transport on this leg. Applicable only when is_temperature_controlled is True. Used for cold chain compliance validation and cargo acceptance rules.',
    `timezone_destination` STRING COMMENT 'IANA timezone identifier for the destination node (e.g., Asia/Singapore, Europe/Frankfurt). Required to correctly interpret standard_arrival_time and compute accurate ETA in local destination time for delivery scheduling.',
    `timezone_origin` STRING COMMENT 'IANA timezone identifier for the origin node (e.g., America/New_York, Europe/London). Required to correctly interpret cutoff_time and standard_departure_time for cross-timezone route planning and ETA calculations.',
    `tracking_method` STRING COMMENT 'Method used to track shipment progress on this leg. GPS for road/fleet, AIS (Automatic Identification System) for ocean vessels, EDI_MILESTONE for carrier EDI updates, API_CARRIER for direct carrier API integration, RFID for warehouse handoffs, or MANUAL for exception-based updates. Drives FourKites data ingestion configuration.. Valid values are `GPS|RFID|EDI_MILESTONE|API_CARRIER|MANUAL|AIS`',
    `transport_mode` STRING COMMENT 'Primary mode of transport for this leg. Drives carrier selection, rate calculation, customs filing requirements (IATA for air, IMO for ocean), and ETA computation. Supports multi-modal freight forwarding decomposition (air + road, ocean + rail).. Valid values are `AIR|OCEAN|ROAD|RAIL|MULTIMODAL|COURIER`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this corridor leg record was last modified, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for incremental data pipeline processing, change data capture (CDC), and audit trail maintenance.',
    `vehicle_type` STRING COMMENT 'Type of vehicle, vessel, or aircraft used on this leg (e.g., B747F for air freighter, 20FT_CONTAINER for ocean, SEMI_TRAILER for road, FLATCAR for rail). Determines capacity constraints, dangerous goods handling rules per IMDG/ICAO TI, and emissions factors for CO2e calculation.',
    CONSTRAINT pk_corridor_leg PRIMARY KEY(`corridor_leg_id`)
) COMMENT 'Individual transport leg within a service corridor, representing a single node-to-node movement segment. Captures leg sequence number, origin node, destination node, transport mode, carrier type, leg distance, standard leg transit time (hours), cut-off time, departure frequency, and leg status. Enables multi-modal route decomposition for freight forwarding (air + road, ocean + rail) and supports load optimization in Oracle TMS. A corridor has one or more legs; each leg is independently trackable via FourKites.';

CREATE OR REPLACE TABLE `transport_shipping_ecm`.`route`.`route_delivery_zone` (
    `route_delivery_zone_id` BIGINT COMMENT 'Unique surrogate identifier for the delivery zone record. Primary key for the route_delivery_zone data product. Entity role: MASTER_RESOURCE — represents a geographic zone asset managed by Transport Shipping for last-mile routing and serviceability.',
    `network_node_id` BIGINT COMMENT 'Foreign key linking to route.network_node. Business justification: route_delivery_zone is currently SILOED (no inbound or outbound FKs). It has hub_node_code (STRING) which is a denormalized code reference to the hub serving this last-mile zone. Adding hub_node_id as',
    `agent_id` BIGINT COMMENT 'Foreign key linking to network.agent. Business justification: Last-mile delivery zones are frequently serviced by local agents. Required for agent commission calculation, service coverage validation, and agent performance tracking. Essential for agent-based dist',
    `depot_id` BIGINT COMMENT 'Foreign key linking to fleet.fleet_depot. Business justification: Delivery zones are served from specific depots; linking enables territory management, last-mile route planning, depot workload balancing, and service coverage analysis.',
    `aeo_required` BOOLEAN COMMENT 'Indicates whether AEO (Authorized Economic Operator) certification is required for carriers operating within this zone. Relevant for cross-border and customs-controlled zones. Enforced during carrier selection in Descartes Customs and SAP TM.',
    `applicable_service_products` STRING COMMENT 'Pipe-separated list of service product codes eligible for delivery within this zone (e.g., EXPRESS|STANDARD|ECONOMY|FREIGHT). Drives service product availability validation during shipment booking and carrier selection in SAP TM. [ENUM-REF-CANDIDATE: promote to reference product for zone-service-product association]',
    `area_sqkm` DECIMAL(18,2) COMMENT 'Total geographic area of the delivery zone in square kilometres. Used in network density analysis, carrier capacity planning, and cost-per-delivery benchmarking in Blue Yonder network design.',
    `carrier_code` STRING COMMENT 'Code of the primary carrier or last-mile delivery partner assigned to service this zone. Used in carrier selection logic within SAP TM and Oracle TMS. May be overridden by dynamic carrier selection based on capacity and cost.. Valid values are `^[A-Z0-9_-]{2,15}$`',
    `city_name` STRING COMMENT 'Name of the primary city or municipality associated with the delivery zone. Used for last-mile dispatch assignment, carrier lane allocation, and customer-facing serviceability lookup.',
    `co2e_factor_kg_per_shipment` DECIMAL(18,2) COMMENT 'Estimated CO2e (Carbon Dioxide Equivalent) emission factor in kilograms per shipment for last-mile delivery within this zone. Used for GHG (Greenhouse Gas) emissions reporting, EU ETS compliance, and CORSIA carbon offsetting calculations.',
    `cod_restricted` BOOLEAN COMMENT 'Indicates whether Cash on Delivery (COD) service is restricted or unavailable within this delivery zone. COD restrictions may apply due to security concerns, carrier capability limitations, or local regulatory requirements. Referenced during e-commerce fulfillment order validation.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 three-letter country code where the delivery zone is located (e.g., GBR, SGP, USA, DEU). Used for customs compliance, regulatory routing rules, and cross-border serviceability validation per WCO and IMO standards.. Valid values are `^[A-Z]{3}$`',
    `coverage_geojson` STRING COMMENT 'GeoJSON-encoded polygon or multipolygon representing the precise geographic boundary of the delivery zone. Used for GPS-based serviceability validation, FourKites real-time visibility geofencing, and last-mile dispatch optimization. Stored as serialized GeoJSON string per RFC 7946.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this delivery zone record was first created in the system (yyyy-MM-ddTHH:mm:ss.SSSXXX). Provides audit trail for zone master data governance and SOX compliance.',
    `customs_zone_type` STRING COMMENT 'Classification of the zone from a customs and trade compliance perspective: domestic (standard domestic territory), ftz (Free Trade Zone), bonded (customs bonded area), international (cross-border delivery zone), special_economic (Special Economic Zone). Used in Descartes Customs for trade compliance routing and ISF/AMS filing requirements.. Valid values are `domestic|ftz|bonded|international|special_economic`',
    `dg_restricted` BOOLEAN COMMENT 'Indicates whether the transport of dangerous goods (DG) is restricted or prohibited within this delivery zone. Enforced during shipment booking validation and carrier selection. Aligned with IMDG Code, ICAO Technical Instructions, and local regulatory requirements.',
    `effective_from` DATE COMMENT 'Date from which this delivery zone definition becomes operationally effective. Used for temporal zone management, ensuring routing and pricing rules apply only within the valid date range. Supports zone versioning and network change management.',
    `effective_until` DATE COMMENT 'Date after which this delivery zone definition is no longer operationally effective. Null for open-ended zones with no planned expiry. Used for zone versioning, network restructuring, and historical serviceability audit.',
    `hub_node_code` STRING COMMENT 'Code of the hub, depot, or distribution center assigned to service this delivery zone in the hub-and-spoke network topology. Drives carrier selection, load optimization, and last-mile dispatch routing in SAP TM and Oracle TMS.. Valid values are `^[A-Z0-9_-]{2,15}$`',
    `isf_required` BOOLEAN COMMENT 'Indicates whether an Importer Security Filing (ISF) is required for shipments entering this zone. Applicable to US import zones under CBP 10+2 rule. Used in Descartes Customs for automated compliance filing.',
    `latitude` DECIMAL(18,2) COMMENT 'Decimal latitude of the geographic centroid of the delivery zone in WGS84 coordinate system. Used for distance-based routing calculations, GPS geofencing in FourKites, and network optimization in Blue Yonder.',
    `longitude` DECIMAL(18,2) COMMENT 'Decimal longitude of the geographic centroid of the delivery zone in WGS84 coordinate system. Used for distance-based routing calculations, GPS geofencing in FourKites, and network optimization in Blue Yonder.',
    `max_dim_weight_kg` DECIMAL(18,2) COMMENT 'Maximum dimensional weight (DIM weight) in kilograms accepted for delivery within this zone. DIM weight is calculated from volumetric dimensions and used alongside actual weight for carrier charge calculation and capacity planning.',
    `max_length_cm` DECIMAL(18,2) COMMENT 'Maximum allowable length in centimetres for a single shipment piece accepted for delivery within this zone. Used in oversized shipment validation during booking and load optimization in Oracle TMS.',
    `max_weight_kg` DECIMAL(18,2) COMMENT 'Maximum gross weight in kilograms for a single shipment accepted for delivery within this zone. Enforced during shipment booking validation and load optimization. Reflects infrastructure, vehicle, and carrier capability constraints.',
    `otd_target_pct` DECIMAL(18,2) COMMENT 'Target On-Time Delivery (OTD) percentage for this zone, expressed as a decimal percentage (e.g., 98.50 = 98.5%). Used as the KPI benchmark for carrier performance management and network optimization reporting.',
    `oversized_restricted` BOOLEAN COMMENT 'Indicates whether oversized or overweight shipments are restricted within this delivery zone due to infrastructure limitations, road access constraints, or local regulations. Used in load optimization and carrier selection in Oracle TMS.',
    `peak_surcharge` BOOLEAN COMMENT 'Indicates whether a peak season surcharge is applicable for this zone during designated peak periods (e.g., holiday season, Chinese New Year). Drives dynamic pricing adjustments in SAP TM charge calculation.',
    `postal_code_from` STRING COMMENT 'Starting postal code of the range covered by this delivery zone. Together with postal_code_to, defines the postal code band for zone membership evaluation. Used in SAP TM zone-based routing and pricing surcharge determination.',
    `postal_code_to` STRING COMMENT 'Ending postal code of the range covered by this delivery zone. Together with postal_code_from, defines the postal code band for zone membership evaluation. Null if the zone is defined by a single postal code or polygon only.',
    `remote_area_surcharge` BOOLEAN COMMENT 'Indicates whether a remote area surcharge (RAS) applies to shipments delivered within this zone. Remote area surcharges are applied by carriers for zones with limited accessibility or extended delivery routes. Referenced by the pricing and rating domain for charge calculation.',
    `residential_surcharge` BOOLEAN COMMENT 'Indicates whether a residential delivery surcharge applies to shipments within this zone. Residential surcharges are levied by carriers for deliveries to non-commercial addresses. Used in pricing and rating charge calculation for B2C and e-commerce fulfillment.',
    `service_cutoff_time` TIMESTAMP COMMENT 'Latest time of day (HH:MM, 24-hour local time) by which a shipment must be tendered to the hub to achieve the standard transit time for this zone. Critical for last-mile dispatch scheduling and customer booking cutoff enforcement.',
    `service_days` STRING COMMENT 'Pipe-separated list of days of the week on which delivery service operates within this zone (e.g., MON|TUE|WED|THU|FRI). Used for ETA calculation, SLA management, and dispatch scheduling. Supports zones with restricted weekend or holiday service.',
    `serviceable` BOOLEAN COMMENT 'Master serviceability flag indicating whether Transport Shipping currently provides delivery service within this zone. A zone may be defined but temporarily unserviceable due to operational, regulatory, or capacity constraints. Used as the primary gate in shipment booking serviceability checks.',
    `sla_standard_code` STRING COMMENT 'Code referencing the standard SLA profile applicable to this delivery zone. Defines OTD (On-Time Delivery) and OTIF (On-Time In-Full) performance targets. Used in SLA entitlement validation and KPI reporting.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `standard_transit_days` STRING COMMENT 'Standard number of business days required to deliver a shipment from the assigned hub node to any address within this zone under normal operating conditions. Used as the baseline for SLA commitment, OTD measurement, and customer ETA communication.',
    `state_province_code` STRING COMMENT 'ISO 3166-2 subdivision code for the state, province, or region within the country (e.g., US-CA, GB-ENG, AU-NSW). Used for sub-national routing rules, tax jurisdiction mapping, and regional SLA configuration.. Valid values are `^[A-Z0-9-]{2,10}$`',
    `temperature_controlled_capable` BOOLEAN COMMENT 'Indicates whether temperature-controlled (cold chain) delivery is available within this zone. Used during shipment booking to validate serviceability for pharmaceutical, perishable, and temperature-sensitive cargo.',
    `timezone` STRING COMMENT 'IANA timezone identifier for the delivery zone (e.g., Europe/London, Asia/Singapore, America/New_York). Used to correctly interpret service cutoff times, ETA/ETD calculations, and SLA breach detection in FourKites and SAP TM.',
    `transit_time_hours` STRING COMMENT 'Standard transit time expressed in total hours for time-definite and express service products where sub-day precision is required. Complements standard_transit_days for same-day, next-day, and time-critical shipment SLA management.',
    `transport_mode` STRING COMMENT 'Primary transport mode used for last-mile delivery within this zone. Determines carrier eligibility, equipment type, and routing logic in SAP TM and Oracle TMS. Multimodal zones support more than one mode.. Valid values are `road|air|ocean|rail|multimodal`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this delivery zone record was last modified (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for change data capture (CDC), data lineage tracking, and master data governance audit.',
    `zone_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the delivery zone across systems (SAP TM, Oracle TMS, FourKites). Used as the business key for zone-based routing, surcharge lookup, and carrier selection. Maps to the zone identifier in SAP TM zone-based routing configuration.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `zone_description` STRING COMMENT 'Free-text description providing additional context about the delivery zone, including notable geographic features, operational constraints, special handling instructions, or historical notes. Used by operations and network planning teams.',
    `zone_group_code` STRING COMMENT 'Code of the zone group or zone cluster to which this delivery zone belongs. Zone groups aggregate individual zones for pricing rate card application, carrier contract negotiation, and network planning. Used in SAP TM zone group configuration.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `zone_name` STRING COMMENT 'Human-readable name of the delivery zone (e.g., Greater London Last-Mile Zone, Singapore CBD Service Area). Used in operational dashboards, carrier communications, and customer-facing serviceability checks.',
    `zone_status` STRING COMMENT 'Current lifecycle status of the delivery zone. Active zones are eligible for shipment routing and serviceability validation. Inactive or retired zones are excluded from new shipment assignments. Suspended zones may be temporarily blocked due to operational or regulatory reasons.. Valid values are `active|inactive|suspended|pending|retired`',
    `zone_tier` STRING COMMENT 'Service tier classification of the zone reflecting delivery density, infrastructure quality, and cost profile (e.g., tier_1 = major urban centre, tier_4 = remote/rural). Used in pricing rate card assignment, SLA differentiation, and network optimization in Blue Yonder.. Valid values are `tier_1|tier_2|tier_3|tier_4`',
    `zone_type` STRING COMMENT 'Classification of the zone by its definition methodology: postal (based on postal code ranges), administrative (country/state/city boundaries), custom (business-defined polygon), last_mile (final delivery leg zone), service_area (carrier or hub service coverage area). Drives routing logic and surcharge applicability in SAP TM.. Valid values are `postal|administrative|custom|last_mile|service_area`',
    CONSTRAINT pk_route_delivery_zone PRIMARY KEY(`route_delivery_zone_id`)
) COMMENT 'Geographic zone definition used for last-mile routing, service area delineation, postal zone mapping, and serviceability validation across all transport modes. Captures zone code, zone name, zone type (postal, administrative, custom, last-mile, service-area), country, state/province, city, postal code range, coverage polygon (GeoJSON), assigned hub node, standard transit time, surcharge applicability (remote area, residential), service restrictions (dangerous goods, oversized, COD), applicable service products, and zone status. SSOT for geographic coverage and serviceability master data referenced by pricing (surcharges), fulfillment (dispatch), SAP TM (zone-based routing), and carrier selection.';

CREATE OR REPLACE TABLE `transport_shipping_ecm`.`route`.`transit_time_standard` (
    `transit_time_standard_id` BIGINT COMMENT 'Unique surrogate identifier for the transit time standard record. Primary key for this entity in the route domain Silver layer.',
    `agreement_id` BIGINT COMMENT 'Foreign key linking to contract.agreement. Business justification: Transit time standards are contractually committed SLA baselines. Linking to agreement enables automated compliance verification, breach detection, and penalty/incentive calculation. Required for cont',
    `carrier_id` BIGINT COMMENT 'Reference to the carrier or transport service provider for whom this transit time standard is defined. Used in SAP TM carrier selection logic.',
    `carrier_service_id` BIGINT COMMENT 'Reference to the logistics service product (e.g., express parcel, economy freight) for which this transit time standard is defined.',
    `route_delivery_zone_id` BIGINT COMMENT 'Foreign key linking to route.route_delivery_zone. Business justification: transit_time_standard captures origin_zone_code as a STRING, which is a denormalized reference to the origin route_delivery_zone. Adding origin_route_delivery_zone_id as a FK to route.route_delivery_z',
    `lane_id` BIGINT COMMENT 'Reference to the origin-destination lane master record that this transit time standard applies to. Links to the lane product in the route domain.',
    `service_corridor_id` BIGINT COMMENT 'Foreign key linking to route.service_corridor. Business justification: transit_time_standard is the authoritative transit time standard for a lane, corridor, or service product combination. The network_corridor_code STRING field is a denormalized reference to a service c',
    `superseded_by_transit_time_standard_id` BIGINT COMMENT 'Self-referencing identifier pointing to the newer transit time standard record that replaces this one when lifecycle_status is SUPERSEDED. Enables version chain traversal for historical SLA analysis.',
    `blue_yonder_standard_code` STRING COMMENT 'External identifier from Blue Yonder Supply Chain Planning that maps this transit time standard to the network design and demand forecasting outputs. Enables traceability between the route domain SSOT and Blue Yonder optimization results.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this transit time standard record was first created in the system. Audit trail field supporting SOX compliance and data lineage in the Databricks Silver layer.',
    `customs_clearance_days` STRING COMMENT 'Number of days allocated for customs clearance included within the standard transit time for cross-border shipments. Used in Descartes Customs integration and trade compliance planning. Relevant for DDP, DAP, and CIF Incoterms.',
    `cutoff_time` TIMESTAMP COMMENT 'The latest time of day (HH:MM, 24-hour local) by which a shipment must be tendered at the origin node to qualify for this transit time standard on a given day. Used in shipment booking, load optimization in Oracle TMS, and SLA management.',
    `cutoff_timezone` STRING COMMENT 'IANA timezone identifier for the cut-off time (e.g., America/New_York, Europe/London). Ensures unambiguous interpretation of cutoff_time across global operations.',
    `delivery_timezone` STRING COMMENT 'IANA timezone identifier for the delivery time window at the destination node (e.g., Asia/Singapore, America/Los_Angeles). Ensures unambiguous interpretation of first_available_delivery_time and latest_delivery_time.',
    `destination_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the destination location of this transit time standard. Used in cross-border routing, customs compliance, and trade lane analytics.. Valid values are `^[A-Z]{3}$`',
    `destination_node_code` STRING COMMENT 'Code identifying the destination hub, depot, port, airport, or facility node for this transit time standard. Aligns with IATA airport codes, UN/LOCODE, or internal network node identifiers.. Valid values are `^[A-Z0-9]{2,10}$`',
    `destination_node_type` STRING COMMENT 'Classification of the destination node (e.g., airport, seaport, Inland Container Depot (ICD), Container Freight Station (CFS), Free Trade Zone (FTZ)). Supports network topology and hub-and-spoke configuration. [ENUM-REF-CANDIDATE: AIRPORT|SEAPORT|RAIL_TERMINAL|ROAD_HUB|WAREHOUSE|ICD|CFS|FTZ — 8 candidates stripped; promote to reference product]',
    `destination_zone_code` STRING COMMENT 'Postal or geographic zone code for the destination area, used in last-mile delivery zone mapping and zone-based transit time calculations in SAP TM and Oracle TMS.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `effective_from` DATE COMMENT 'The date from which this transit time standard becomes valid and applicable for SLA commitments, ETA calculation, and carrier selection. Supports temporal versioning of transit standards.',
    `effective_until` DATE COMMENT 'The date after which this transit time standard is no longer valid. Null indicates an open-ended standard with no planned expiry. Used in contract SLA management and carrier selection logic.',
    `first_available_delivery_time` TIMESTAMP COMMENT 'The earliest time of day (HH:MM, 24-hour local) at which delivery can be attempted at the destination under this transit time standard. Used in last-mile scheduling, delivery window commitments, and ePOD (Electronic Proof of Delivery) planning.',
    `frequency_type` STRING COMMENT 'Frequency at which this transit service operates on the lane (e.g., daily, weekly, bi-weekly). Used in load planning, capacity allocation, and network optimization outputs from Blue Yonder.. Valid values are `DAILY|WEEKLY|BI_WEEKLY|MONTHLY|ON_DEMAND`',
    `hazmat_applicable` BOOLEAN COMMENT 'Indicates whether this transit time standard applies to hazardous materials shipments. When true, IMDG Code (ocean) or ICAO Technical Instructions (air) dangerous goods regulations govern the transit. Affects carrier selection and routing.',
    `hub_routing_required` BOOLEAN COMMENT 'Indicates whether this transit time standard requires routing through an intermediate hub node (hub-and-spoke configuration). When true, hub transit time is included in standard_transit_days.',
    `incoterms_applicability` STRING COMMENT 'Pipe-separated list of International Commercial Terms (Incoterms) under which this transit time standard applies (e.g., DDP|DAP|FOB|CIF|EXW). Governs responsibility boundaries for transit time SLA. [ENUM-REF-CANDIDATE: DDP|DAP|FOB|CIF|EXW|FCA|CPT|CIP|FAS|CFR|DPU|EXW — promote to reference product]',
    `intermediate_hub_code` STRING COMMENT 'Code of the primary intermediate hub node through which shipments are routed when hub_routing_required is true. Aligns with IATA airport codes or internal network node identifiers.. Valid values are `^[A-Z0-9]{2,10}$`',
    `latest_delivery_time` TIMESTAMP COMMENT 'The latest time of day (HH:MM, 24-hour local) by which delivery must be completed at the destination to meet this transit time standard. Used in SLA compliance measurement and On-Time In-Full (OTIF) reporting.',
    `lifecycle_status` STRING COMMENT 'Current operational state of this transit time standard in its lifecycle. ACTIVE records are used in ETA calculation and carrier selection. SUPERSEDED records are retained for historical SLA audit. DRAFT records are pending approval.. Valid values are `ACTIVE|INACTIVE|DRAFT|SUPERSEDED|SUSPENDED`',
    `max_volume_cbm` DECIMAL(18,2) COMMENT 'Maximum shipment volume in Cubic Meters (CBM) eligible for this transit time standard. Used alongside max_weight_kg and Dimensional Weight (DIM Weight) rules for load optimization in Oracle TMS.',
    `max_weight_kg` DECIMAL(18,2) COMMENT 'Maximum gross weight in kilograms of a shipment eligible for this transit time standard. Shipments exceeding this threshold require a different standard or special handling arrangement.',
    `operating_days_mask` STRING COMMENT '7-character binary string (Mon-Sun) indicating which days of the week this transit time standard is active (1=active, 0=inactive). Example: 1111100 = Monday to Friday only. Encodes day-of-week restrictions for scheduling and ETA calculation.. Valid values are `^[01]{7}$`',
    `origin_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the origin location of this transit time standard. Used in cross-border routing, customs compliance, and trade lane analytics.. Valid values are `^[A-Z]{3}$`',
    `origin_node_code` STRING COMMENT 'Code identifying the origin hub, depot, port, airport, or facility node for this transit time standard. Aligns with IATA airport codes, UN/LOCODE, or internal network node identifiers.. Valid values are `^[A-Z0-9]{2,10}$`',
    `origin_node_type` STRING COMMENT 'Classification of the origin node (e.g., airport, seaport, Inland Container Depot (ICD), Container Freight Station (CFS), Free Trade Zone (FTZ)). Supports network topology analysis and hub-and-spoke configuration. [ENUM-REF-CANDIDATE: AIRPORT|SEAPORT|RAIL_TERMINAL|ROAD_HUB|WAREHOUSE|ICD|CFS|FTZ — 8 candidates stripped; promote to reference product]',
    `sap_tm_route_code` STRING COMMENT 'External route identifier from SAP TM used to link this transit time standard to the corresponding route planning and freight order management record in SAP TM. Supports system-of-record traceability.',
    `shipment_type` STRING COMMENT 'Type of shipment load for which this transit time standard applies: Full Truckload (FTL), Less Than Truckload (LTL), Full Container Load (FCL), Less Than Container Load (LCL), parcel, pallet, or bulk. Drives carrier selection and load optimization. [ENUM-REF-CANDIDATE: FTL|LTL|FCL|LCL|PARCEL|PALLET|BULK — 7 candidates stripped; promote to reference product]',
    `standard_code` STRING COMMENT 'Externally-known unique business code identifying this transit time standard record, used in SAP TM, Oracle TMS, and FourKites integrations for ETA calculation and carrier selection.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `standard_description` STRING COMMENT 'Free-text description providing additional context about this transit time standard, including special conditions, exceptions, or operational notes relevant to SLA management and carrier selection.',
    `standard_name` STRING COMMENT 'Human-readable descriptive name for this transit time standard, used in reporting, SLA contract references, and carrier selection displays.',
    `standard_transit_days` STRING COMMENT 'The planned number of calendar or business days for transit from origin to destination under this standard. Principal quantitative fact for this resource. Used in SLA commitments, ETA calculation in FourKites, and On-Time Delivery (OTD) performance measurement.',
    `standard_transit_hours` STRING COMMENT 'The planned number of hours for transit from origin to destination under this standard. Provides sub-day precision for express and same-day services. Complements standard_transit_days for precise ETA calculation in FourKites.',
    `temperature_controlled` BOOLEAN COMMENT 'Indicates whether this transit time standard applies to temperature-controlled (cold chain) shipments. Affects carrier selection, equipment requirements, and SLA commitments for perishable or pharmaceutical cargo.',
    `transit_day_type` STRING COMMENT 'Specifies whether standard_transit_days is measured in calendar days, business days, or working days. Critical for accurate SLA commitment and ETA calculation, particularly for cross-border shipments with customs clearance.. Valid values are `CALENDAR|BUSINESS|WORKING`',
    `transport_mode` STRING COMMENT 'Primary mode of transport for this transit time standard. Aligns with IATA (air), IMO (ocean), and DOT (road/rail) classifications. Drives carrier selection and ETA logic in SAP TM and FourKites.. Valid values are `AIR|OCEAN|ROAD|RAIL|MULTIMODAL`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this transit time standard record was last modified. Audit trail field supporting change management, SOX compliance, and incremental data loading in the Databricks Silver layer.',
    `version_number` STRING COMMENT 'Monotonically increasing version counter for this transit time standard record. Incremented each time the standard is revised. Supports temporal versioning and audit trail for SLA compliance and regulatory reporting.',
    CONSTRAINT pk_transit_time_standard PRIMARY KEY(`transit_time_standard_id`)
) COMMENT 'Authoritative transit time standard for a lane, corridor, or service product combination. Captures origin node/zone, destination node/zone, service level (express, standard, economy), transport mode, standard transit days, standard transit hours, cut-off time, first-available-delivery time, day-of-week restrictions, and effective date range. Feeds SLA commitments in the contract domain, ETA calculation in FourKites, and carrier selection logic in SAP TM. Distinct from actual ETA events — this is the planned standard, not the real-time estimate.';

CREATE OR REPLACE TABLE `transport_shipping_ecm`.`route`.`carrier_lane_allocation` (
    `carrier_lane_allocation_id` BIGINT COMMENT 'Unique identifier for the carrier lane allocation record. Primary key.',
    `agreement_id` BIGINT COMMENT 'Foreign key linking to contract.agreement. Business justification: Capacity allocations are governed by master agreements with volume commitments and capacity guarantees. Needed for contract utilization tracking, volume commitment compliance, and capacity planning ag',
    `carrier_id` BIGINT COMMENT 'Reference to the carrier (airline, ocean carrier, road carrier, rail operator) allocated to this lane. Links to carrier master in procurement domain.',
    `carrier_service_id` BIGINT COMMENT 'Foreign key linking to network.carrier_service. Business justification: Capacity allocations are contracted at service-product level (express capacity vs. economy capacity are separate pools). Required for service-specific capacity management, booking validation, and allo',
    `lane_id` BIGINT COMMENT 'Reference to the origin-destination lane or corridor leg to which this carrier is allocated.',
    `rate_card_id` BIGINT COMMENT 'Foreign key linking to pricing.rate_card. Business justification: Carrier allocations reference rate cards for pricing. Rate_card_id links capacity allocation to pricing structure, enabling allocated capacity costing, carrier allocation profitability analysis, and r',
    `tariff_id` BIGINT COMMENT 'Foreign key linking to pricing.tariff. Business justification: Carrier allocations reference tariffs for published rates. Tariff_id links capacity to published pricing, enabling tariff-based allocation costing and regulatory compliance for allocated capacity pric',
    `allocation_code` STRING COMMENT 'Business identifier for this carrier lane allocation, used in SAP TM carrier selection engine and tendering processes.. Valid values are `^[A-Z0-9]{6,20}$`',
    `allocation_notes` STRING COMMENT 'Free-text notes or comments regarding this carrier lane allocation, including special handling instructions, restrictions, or operational considerations.',
    `allocation_percentage` DECIMAL(18,2) COMMENT 'Percentage of lane volume allocated to this carrier, expressed as a decimal (e.g., 35.50 for 35.5%). Used for load balancing and capacity planning.',
    `allocation_status` STRING COMMENT 'Current lifecycle status of the carrier lane allocation. Active allocations are eligible for carrier selection.. Valid values are `active|inactive|suspended|pending|expired`',
    `allocation_type` STRING COMMENT 'Type of allocation: contracted (long-term agreement), spot (ad-hoc booking), backup (contingency), seasonal (time-bound), or preferred (strategic partner).. Valid values are `contracted|spot|backup|seasonal|preferred`',
    `api_integration_enabled` BOOLEAN COMMENT 'Indicates whether API integration is enabled for real-time booking, tracking, and rate queries with this carrier on this lane.',
    `approval_status` STRING COMMENT 'Approval workflow status for this carrier lane allocation. Only approved allocations are activated for carrier selection.. Valid values are `draft|pending_approval|approved|rejected`',
    `approved_by_user` STRING COMMENT 'User ID or name of the person who approved this carrier lane allocation.',
    `approved_timestamp` TIMESTAMP COMMENT 'Timestamp when this carrier lane allocation was approved.',
    `carbon_emission_factor_kg_co2e` DECIMAL(18,2) COMMENT 'Carbon emission factor in kilograms of CO2 equivalent per unit (per TEU-km, per ton-km, or per shipment) for this carrier on this lane. Used for GHG (Greenhouse Gas) reporting and sustainability analytics.',
    `carrier_certification_level` STRING COMMENT 'Certification or partnership level of the carrier: standard, preferred, strategic, AEO (Authorized Economic Operator), C-TPAT (Customs-Trade Partnership Against Terrorism), or other industry certifications.. Valid values are `standard|preferred|strategic|certified|aeo|ctpat`',
    `contract_reference` STRING COMMENT 'Reference number of the underlying carrier contract or rate agreement that governs this allocation.. Valid values are `^[A-Z0-9-]{8,30}$`',
    `contracted_capacity_teu` DECIMAL(18,2) COMMENT 'Contracted capacity for ocean freight expressed in TEU (Twenty-foot Equivalent Units). Null for non-ocean modes.',
    `contracted_capacity_volume_cbm` DECIMAL(18,2) COMMENT 'Contracted volume capacity in cubic meters (CBM) for freight. Used for dimensional capacity planning.',
    `contracted_capacity_weight_kg` DECIMAL(18,2) COMMENT 'Contracted weight capacity in kilograms for air, road, or rail freight. Used for capacity management and load optimization.',
    `cost_currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the cost per unit (e.g., USD, EUR, CNY).. Valid values are `^[A-Z]{3}$`',
    `cost_per_unit` DECIMAL(18,2) COMMENT 'Contracted cost per unit (per TEU, per kg, per CBM, or per shipment) for this carrier on this lane. Used for freight cost calculation and carrier selection optimization.',
    `created_by_user` STRING COMMENT 'User ID or name of the person who created this carrier lane allocation record.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this carrier lane allocation record was first created in the system.',
    `customs_bonded` BOOLEAN COMMENT 'Indicates whether this carrier operates under customs bond for in-transit goods, enabling duty-deferred cross-border movements.',
    `cutoff_time` TIMESTAMP COMMENT 'Daily cutoff time (HH:MM format, 24-hour) for booking this carrier on this lane. Bookings after cutoff are processed next business day.',
    `edi_enabled` BOOLEAN COMMENT 'Indicates whether Electronic Data Interchange (EDI) is enabled for automated booking, status updates, and invoicing with this carrier on this lane.',
    `effective_from_date` DATE COMMENT 'Date from which this carrier lane allocation becomes effective and eligible for carrier selection.',
    `effective_to_date` DATE COMMENT 'Date until which this carrier lane allocation remains effective. Null for open-ended allocations.',
    `equipment_type` STRING COMMENT 'Type of equipment or container used by this carrier on this lane (e.g., 20ft dry, 40ft reefer, flatbed truck, aircraft type). Free-text to accommodate diverse equipment specifications.',
    `fuel_surcharge_applicable` BOOLEAN COMMENT 'Indicates whether a fuel surcharge (BAF - Bunker Adjustment Factor for ocean, or fuel surcharge for air/road) is applicable to this allocation.',
    `hazmat_capable` BOOLEAN COMMENT 'Indicates whether this carrier is certified and capable of transporting hazardous materials (HAZMAT) on this lane per IMDG Code or ICAO Technical Instructions.',
    `incoterm` STRING COMMENT 'Applicable Incoterm for this carrier lane allocation, defining the division of costs and risks between shipper and carrier (e.g., FOB, CIF, DDP). [ENUM-REF-CANDIDATE: EXW|FCA|CPT|CIP|DAP|DPU|DDP|FAS|FOB|CFR|CIF — 11 candidates stripped; promote to reference product]',
    `last_modified_by_user` STRING COMMENT 'User ID or name of the person who last modified this carrier lane allocation record.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this carrier lane allocation record was last modified.',
    `lead_time_days` STRING COMMENT 'Required lead time in days for booking this carrier on this lane. Used for tendering and capacity reservation planning.',
    `maximum_volume_limit` DECIMAL(18,2) COMMENT 'Maximum volume limit (in applicable unit: TEU, kg, CBM) that can be allocated to this carrier on this lane per capacity constraints or contract terms.',
    `minimum_volume_commitment` DECIMAL(18,2) COMMENT 'Minimum volume commitment (in applicable unit: TEU, kg, CBM) that the shipper must tender to this carrier on this lane per contract terms.',
    `performance_score` DECIMAL(18,2) COMMENT 'Historical performance score (0-100) for this carrier on this lane, based on OTD (On-Time Delivery), OTIF (On-Time In-Full), claims rate, and service quality KPIs (Key Performance Indicators).',
    `priority_rank` STRING COMMENT 'Priority ranking of this carrier for the lane. Lower numbers indicate higher priority. Used by SAP TM carrier selection engine to determine preferred and backup carriers.',
    `sla_on_time_delivery_pct` DECIMAL(18,2) COMMENT 'Service Level Agreement target for on-time delivery percentage (OTD) for this carrier on this lane, expressed as a decimal (e.g., 95.00 for 95%).',
    `temperature_controlled` BOOLEAN COMMENT 'Indicates whether this carrier provides temperature-controlled (reefer) transport on this lane for perishable or pharmaceutical goods.',
    `transit_time_days` STRING COMMENT 'Standard transit time in days for this carrier on this lane, used for ETA (Estimated Time of Arrival) calculation and service level planning.',
    `transport_mode` STRING COMMENT 'Mode of transport for this carrier allocation (air, ocean, road, rail, multimodal, parcel express).. Valid values are `air|ocean|road|rail|multimodal|parcel`',
    `visibility_enabled` BOOLEAN COMMENT 'Indicates whether real-time shipment visibility is enabled for this carrier on this lane via FourKites or other visibility platforms.',
    CONSTRAINT pk_carrier_lane_allocation PRIMARY KEY(`carrier_lane_allocation_id`)
) COMMENT 'Defines the allocation of a specific carrier (airline, ocean carrier, road carrier, rail operator) to a lane or corridor leg, including contracted capacity, priority ranking, allocation percentage, mode of transport, service type, effective date range, and allocation status. Used by SAP TM carrier selection engine to determine preferred and backup carriers per lane. Supports tendering, spot booking, and capacity management. References carrier master in the procurement domain via FK (linked in a later step).';

CREATE OR REPLACE TABLE `transport_shipping_ecm`.`route`.`plan` (
    `plan_id` BIGINT COMMENT 'Unique identifier for the route plan record. Primary key.',
    `agreement_id` BIGINT COMMENT 'Foreign key linking to contract.agreement. Business justification: Plans execute shipments under master service agreements. Contract compliance tracking, rate application, SLA enforcement, and penalty/incentive calculation all require linking plan execution to govern',
    `network_node_id` BIGINT COMMENT 'Reference to the final destination location (warehouse, port, terminal, customer site) for this route plan.',
    `freight_order_id` BIGINT COMMENT 'Reference to the freight order in SAP TM that triggered this route plan generation.',
    `lane_id` BIGINT COMMENT 'Reference to the predefined origin-destination lane master record that this route plan is based on.',
    `plan_network_node_id` BIGINT COMMENT 'Reference to the starting location (warehouse, port, terminal, customer site) for this route plan.',
    `carrier_id` BIGINT COMMENT 'Reference to the primary carrier (airline, ocean liner, trucking company, rail operator) assigned to execute the majority of this route plan.',
    `rate_card_id` BIGINT COMMENT 'Foreign key linking to pricing.rate_card. Business justification: Route plans use rate cards for cost estimation. Rate_card_id enables planned cost calculation during route optimization, supporting cost-based routing decisions and planned vs. actual cost variance an',
    `service_corridor_id` BIGINT COMMENT 'Reference to the service corridor (geographic trade lane or network segment) that this route plan operates within.',
    `transit_time_standard_id` BIGINT COMMENT 'Foreign key linking to route.transit_time_standard. Business justification: An operational route plan is generated against a governing transit time standard that defines the SLA, cutoff times, and expected transit days for the lane/corridor combination. Linking plan to transi',
    `cancellation_reason` STRING COMMENT 'Free-text explanation of why this route plan was cancelled. Null if plan was not cancelled.',
    `cancellation_timestamp` TIMESTAMP COMMENT 'Timestamp when this route plan was cancelled. Null if plan was not cancelled. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `completion_timestamp` TIMESTAMP COMMENT 'Timestamp when this route plan was completed (final leg arrival at destination). Null if not yet completed. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `confirmed_timestamp` TIMESTAMP COMMENT 'Timestamp when this route plan was confirmed and approved for execution. Null if plan is still in draft status. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this route plan record was first created in the system. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `destination_address` STRING COMMENT 'Full address of the destination location including street, city, postal code, and country. Business-confidential organizational contact data.',
    `destination_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the destination location (e.g., USA, DEU, CHN).. Valid values are `^[A-Z]{3}$`',
    `execution_start_timestamp` TIMESTAMP COMMENT 'Timestamp when execution of this route plan began (first leg departure). Null if execution has not started. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `incoterm` STRING COMMENT 'Incoterm governing the delivery terms and responsibility transfer point for this shipment: EXW (Ex Works), FCA (Free Carrier), CPT (Carriage Paid To), CIP (Carriage and Insurance Paid To), DAP (Delivered at Place), DPU (Delivered at Place Unloaded), DDP (Delivered Duty Paid), FAS (Free Alongside Ship), FOB (Free on Board), CFR (Cost and Freight), CIF (Cost Insurance and Freight). [ENUM-REF-CANDIDATE: EXW|FCA|CPT|CIP|DAP|DPU|DDP|FAS|FOB|CFR|CIF — 11 candidates stripped; promote to reference product]',
    `is_cross_border` BOOLEAN COMMENT 'Indicates whether this route plan crosses international borders and requires customs clearance. True if cross-border, False if domestic.',
    `is_hazmat` BOOLEAN COMMENT 'Indicates whether this route plan involves the transport of dangerous goods or hazardous materials requiring special handling and compliance. True if hazmat, False otherwise.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this route plan record was last updated. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `notes` STRING COMMENT 'Free-text notes or special instructions related to this route plan, such as handling requirements, customer preferences, or operational constraints.',
    `number_of_legs` STRING COMMENT 'Total number of transport legs (segments) in this route plan. Each leg represents movement between two consecutive nodes.',
    `number_of_stops` STRING COMMENT 'Total number of intermediate stops (hubs, terminals, cross-docks) between origin and destination, excluding origin and destination.',
    `optimization_objective` STRING COMMENT 'Primary optimization goal used by the planning system: Cost (minimize freight cost), Time (minimize transit time), CO2e (minimize carbon emissions), or Balanced (multi-objective optimization).. Valid values are `COST|TIME|CO2E|BALANCED`',
    `origin_address` STRING COMMENT 'Full address of the origin location including street, city, postal code, and country. Business-confidential organizational contact data.',
    `origin_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the origin location (e.g., USA, DEU, CHN).. Valid values are `^[A-Z]{3}$`',
    `plan_status` STRING COMMENT 'Current lifecycle status of the route plan: Draft (under planning), Confirmed (approved for execution), In Execution (actively being executed), Completed (successfully finished), Cancelled (terminated before completion), or Failed (execution unsuccessful).. Valid values are `DRAFT|CONFIRMED|IN_EXECUTION|COMPLETED|CANCELLED|FAILED`',
    `planned_arrival_timestamp` TIMESTAMP COMMENT 'Planned Estimated Time of Arrival (ETA) at the destination location. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `planned_co2e_emissions_kg` DECIMAL(18,2) COMMENT 'Estimated total greenhouse gas emissions for this route plan, measured in kilograms of CO2 equivalent (CO2e). Used for sustainability reporting and carbon offsetting.',
    `planned_cost_amount` DECIMAL(18,2) COMMENT 'Total planned cost for executing this route plan, including carrier charges, fuel surcharges, and terminal handling charges. Business-confidential financial data.',
    `planned_cost_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the planned cost amount (e.g., USD, EUR, GBP).. Valid values are `^[A-Z]{3}$`',
    `planned_departure_timestamp` TIMESTAMP COMMENT 'Planned Estimated Time of Departure (ETD) from the origin location. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `planning_source_system` STRING COMMENT 'System that generated this route plan: SAP TM (Transportation Management), Blue Yonder (Supply Chain Planning), Oracle TMS, or manual planning.. Valid values are `SAP_TM|BLUE_YONDER|ORACLE_TMS|MANUAL`',
    `planning_timestamp` TIMESTAMP COMMENT 'Timestamp when this route plan was generated or last re-optimized by the planning system. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `reference_number` STRING COMMENT 'Externally-known unique business identifier for the route plan, generated by SAP TM or Blue Yonder. Used for cross-system tracking and customer communication.. Valid values are `^[A-Z0-9]{8,20}$`',
    `requires_customs_clearance` BOOLEAN COMMENT 'Indicates whether this route plan requires customs brokerage and trade compliance processing. True if customs clearance is required, False otherwise.',
    `service_type` STRING COMMENT 'Service level for this route plan: Express, Standard, Economy, Dedicated, LTL (Less Than Truckload), FTL (Full Truckload), FCL (Full Container Load), or LCL (Less Than Container Load). [ENUM-REF-CANDIDATE: EXPRESS|STANDARD|ECONOMY|DEDICATED|LTL|FTL|FCL|LCL — 8 candidates stripped; promote to reference product]',
    `sla_target_delivery_timestamp` TIMESTAMP COMMENT 'Contractual SLA target timestamp for delivery at destination. Used to measure On-Time Delivery (OTD) and On-Time In-Full (OTIF) performance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `temperature_controlled` BOOLEAN COMMENT 'Indicates whether this route plan requires temperature-controlled transport (refrigerated or climate-controlled). True if temperature control is required, False otherwise.',
    `total_planned_distance_km` DECIMAL(18,2) COMMENT 'Total planned distance for the entire route from origin to destination, measured in kilometers. Sum of all leg distances.',
    `total_planned_transit_time_hours` DECIMAL(18,2) COMMENT 'Total planned transit time for the entire route from origin to destination, measured in hours. Includes transport time and planned dwell time at intermediate nodes.',
    `transport_mode` STRING COMMENT 'Primary mode of transportation for this route plan: Air, Ocean, Road, Rail, Multimodal (combination), or Parcel (express delivery).. Valid values are `AIR|OCEAN|ROAD|RAIL|MULTIMODAL|PARCEL`',
    `version` STRING COMMENT 'Version number of this route plan. Incremented when the plan is re-optimized or modified. Version 1 is the initial plan.',
    `visibility_tracking_enabled` BOOLEAN COMMENT 'Indicates whether real-time visibility tracking via FourKites or similar platform is enabled for this route plan. True if tracking is active, False otherwise.',
    CONSTRAINT pk_plan PRIMARY KEY(`plan_id`)
) COMMENT 'Operational route plan generated by SAP TM or Blue Yonder for a specific shipment or freight order, representing the planned sequence of nodes, legs, carriers, and timing for end-to-end movement. Captures plan reference number, planning source system, transport mode, total planned distance, total planned transit time, planned ETD, planned ETA, number of legs, optimization objective (cost/time/CO2e), plan status (draft, confirmed, executed, cancelled), and plan version. Transactional — a new plan is created per shipment or freight order planning event.';

CREATE OR REPLACE TABLE `transport_shipping_ecm`.`route`.`plan_leg` (
    `plan_leg_id` BIGINT COMMENT 'Unique identifier for the route plan leg. Primary key for this entity.',
    `broker_assignment_id` BIGINT COMMENT 'Foreign key linking to customs.broker_assignment. Business justification: Plan leg execution requires tracking which customs broker is handling clearance at that legs port of entry/exit. Critical for coordinating documentation handoff, filing deadlines, and release timing ',
    `carrier_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.carrier_agreement. Business justification: Individual leg execution must reference carrier contract for buy-rate validation, carrier performance measurement against SLAs, and cost reconciliation. Critical for carrier invoice validation and dis',
    `carrier_buy_rate_id` BIGINT COMMENT 'Foreign key linking to pricing.carrier_buy_rate. Business justification: Route plan legs use carrier buy rates for cost. Carrier_buy_rate_id enables leg-level cost calculation, supporting multi-leg cost optimization, carrier selection by leg, and leg-level margin analysis.',
    `carrier_id` BIGINT COMMENT 'Reference to the carrier or transportation service provider executing this leg. Links to the carrier master data for the airline, shipping line, trucking company, or rail operator.',
    `carrier_schedule_id` BIGINT COMMENT 'Foreign key linking to route.carrier_schedule. Business justification: plan_leg represents the planned execution of a transport leg, which is typically booked against a specific published carrier schedule (flight, vessel voyage, truck departure). Linking plan_leg to carr',
    `carrier_service_id` BIGINT COMMENT 'Foreign key linking to network.carrier_service. Business justification: Each executed leg operates under a specific carrier service contract. Required for accurate cost calculation, service-level SLA compliance validation, and invoice reconciliation. Enables service-speci',
    `container_unit_id` BIGINT COMMENT 'Foreign key linking to fleet.container_unit. Business justification: Intermodal shipments require tracking which container is assigned to each leg for equipment positioning, empty repositioning, depot inventory management, and container lifecycle tracking.',
    `corridor_leg_id` BIGINT COMMENT 'Foreign key linking to route.corridor_leg. Business justification: plan_leg is the operational execution of a single transport leg within a route plan. corridor_leg is the master definition of that same leg within a service corridor. Linking plan_leg to corridor_leg ',
    `declaration_id` BIGINT COMMENT 'Foreign key linking to customs.declaration. Business justification: Cross-border legs trigger customs declarations. Required for leg-level customs clearance tracking, delay attribution to specific border crossings, and customs status visibility in leg execution.',
    `network_node_id` BIGINT COMMENT 'Reference to the destination location node for this leg. Represents the arrival point such as a warehouse, hub, terminal, or customer location.',
    `driver_profile_id` BIGINT COMMENT 'Reference to the driver assigned to this leg for road transport. Links to workforce master data for driver information.',
    `freight_order_id` BIGINT COMMENT 'Reference to the freight order or shipment being transported on this leg. Enables direct linkage to the shipment execution record in Oracle TMS or SAP TM.',
    `lane_id` BIGINT COMMENT 'Reference to the origin-destination lane master data for this leg. Links to the lane definition that governs transit time standards, carrier allocations, and pricing for this corridor.',
    `plan_id` BIGINT COMMENT 'Reference to the parent route plan that contains this leg. Links this leg to the overall multi-leg route plan for a shipment or freight order.',
    `primary_plan_network_node_id` BIGINT COMMENT 'Reference to the origin location node for this leg. Represents the departure point such as a warehouse, hub, terminal, or customer location.',
    `transport_asset_id` BIGINT COMMENT 'Foreign key linking to fleet.transport_asset. Business justification: Route plan legs specify which vehicle/trailer/container executes each leg—essential for capacity planning, asset utilization tracking, maintenance scheduling, and operational execution visibility.',
    `rate_line_id` BIGINT COMMENT 'Foreign key linking to pricing.rate_line. Business justification: Plan legs execute specific rate line commitments from contracts or rate cards. Enables actual-vs-quoted freight cost analysis, margin tracking, and rate accuracy validation. Critical for freight cost ',
    `shipment_leg_id` BIGINT COMMENT 'Foreign key linking to shipment.shipment_leg. Business justification: Route plan legs (strategic) map to actual shipment legs (tactical execution) when plans are executed. Essential for plan vs. actual variance analysis, performance measurement, delay attribution, and c',
    `actual_arrival_datetime` TIMESTAMP COMMENT 'Actual arrival date and time for this leg. Captured from real-time tracking systems such as FourKites or carrier EDI messages. Null if leg has not yet arrived.',
    `actual_departure_datetime` TIMESTAMP COMMENT 'Actual departure date and time for this leg. Captured from real-time tracking systems such as FourKites or carrier EDI messages. Null if leg has not yet departed.',
    `actual_transit_hours` DECIMAL(18,2) COMMENT 'Actual transit time for this leg in hours. Calculated as the difference between actual arrival and actual departure times. Used for performance analysis and OTD (On-Time Delivery) measurement.',
    `booking_reference_number` STRING COMMENT 'Carrier booking or reservation number for this leg. Used for ocean freight bookings, air freight reservations, and dedicated transport bookings.',
    `carbon_emissions_kg` DECIMAL(18,2) COMMENT 'Estimated carbon dioxide equivalent (CO2e) emissions for this leg in kilograms. Calculated based on transport mode, distance, and load weight. Used for sustainability reporting and compliance with EU ETS and CORSIA.',
    `cost_amount` DECIMAL(18,2) COMMENT 'Total transportation cost for this leg. Includes base freight charges, fuel surcharges, and accessorial charges. Used for freight audit and cost allocation.',
    `cost_currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the cost amount. Indicates the currency in which the leg cost is denominated (e.g., USD, EUR, GBP).. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this route plan leg record was first created in the system. Audit field for data lineage and compliance.',
    `customs_clearance_required_flag` BOOLEAN COMMENT 'Indicates whether this leg crosses an international border and requires customs clearance. True for cross-border legs requiring customs declarations and trade compliance processing.',
    `customs_clearance_status` STRING COMMENT 'Current status of customs clearance for this leg. Tracks the progression through customs processing from submission to release. Integrated with Descartes Customs system.. Valid values are `not_required|pending|cleared|held|released`',
    `delay_minutes` STRING COMMENT 'Total delay time in minutes for this leg. Calculated as the difference between actual and planned arrival times. Null if leg arrived on time or early.',
    `delay_reason_code` STRING COMMENT 'Standardized code indicating the reason for any delay on this leg. Used for root cause analysis and exception management. Examples include weather, customs hold, mechanical failure, traffic congestion.',
    `distance_km` DECIMAL(18,2) COMMENT 'Planned distance for this leg in kilometers. Used for route optimization, cost calculation, and carbon footprint estimation.',
    `equipment_type` STRING COMMENT 'Type of equipment or container used for this leg. Examples include 20ft dry container, 40ft reefer, flatbed trailer, box truck, pallet. Follows carrier and industry equipment classification standards.',
    `flight_number` STRING COMMENT 'Flight number for air freight legs. Identifies the specific airline flight carrying the shipment (e.g., AA1234, LH456).',
    `hazmat_flag` BOOLEAN COMMENT 'Indicates whether this leg transports hazardous materials requiring special handling and compliance with IMDG Code or ICAO Technical Instructions for Dangerous Goods.',
    `leg_sequence_number` STRING COMMENT 'Sequential order of this leg within the parent route plan. Indicates the position of this leg in the multi-leg journey (e.g., 1 for first leg, 2 for second leg).',
    `leg_status` STRING COMMENT 'Current operational status of this route plan leg. Tracks the lifecycle state from planning through execution to completion. Updated by Oracle TMS, SAP TM, and FourKites real-time visibility events.. Valid values are `planned|confirmed|in_transit|completed|delayed|cancelled`',
    `load_type` STRING COMMENT 'Load configuration for this leg. Indicates whether the shipment is Full Truckload (FTL), Less Than Truckload (LTL), Full Container Load (FCL), Less Than Container Load (LCL), or parcel.. Valid values are `FTL|LTL|FCL|LCL|parcel`',
    `notes` STRING COMMENT 'Free-text notes or comments about this leg. Used for special instructions, exception details, or operational remarks that do not fit structured fields.',
    `planned_arrival_datetime` TIMESTAMP COMMENT 'Planned arrival date and time for this leg. Represents the scheduled ETA (Estimated Time of Arrival) at the destination node.',
    `planned_departure_datetime` TIMESTAMP COMMENT 'Planned departure date and time for this leg. Represents the scheduled ETD (Estimated Time of Departure) from the origin node.',
    `planned_transit_hours` DECIMAL(18,2) COMMENT 'Planned transit time for this leg in hours. Calculated as the difference between planned arrival and planned departure times. Used for transit time standard compliance and SLA tracking.',
    `source_system` STRING COMMENT 'Name of the operational system that created or last updated this route plan leg record. Examples include SAP TM, Oracle TMS, Blue Yonder, FourKites. Used for data lineage and reconciliation.',
    `temperature_controlled_flag` BOOLEAN COMMENT 'Indicates whether this leg requires temperature-controlled transport (reefer). True for cold chain shipments requiring refrigeration or climate control.',
    `tracking_number` STRING COMMENT 'Carrier-provided tracking number for this leg. Used for real-time shipment visibility and integration with FourKites tracking platform.',
    `trailer_number` STRING COMMENT 'Trailer or semi-trailer identification number for road freight legs. Used for FTL and LTL shipments.',
    `transport_mode` STRING COMMENT 'Mode of transportation used for this leg. Indicates whether the leg is executed via air freight, ocean freight, road transport, rail, parcel delivery, or intermodal combination.. Valid values are `air|ocean|road|rail|parcel|intermodal`',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this route plan leg record was last modified. Audit field for tracking changes and data quality management.',
    `voyage_number` STRING COMMENT 'Voyage or sailing number for ocean freight legs. Identifies the specific vessel voyage carrying the shipment.',
    CONSTRAINT pk_plan_leg PRIMARY KEY(`plan_leg_id`)
) COMMENT 'Individual leg detail within an operational route plan, capturing the planned execution of a single corridor leg for a specific shipment or freight order. Captures leg sequence, origin node, destination node, carrier, vehicle/vessel/flight reference, planned departure datetime, planned arrival datetime, planned leg transit hours, actual departure datetime, actual arrival datetime, leg status (planned, in-transit, completed, delayed), and delay reason code. Enables leg-level tracking integration with FourKites and exception management in Oracle TMS.';

CREATE OR REPLACE TABLE `transport_shipping_ecm`.`route`.`eta_event` (
    `eta_event_id` BIGINT COMMENT 'Unique identifier for the ETA/ETD event record. Primary key for the eta_event product.',
    `carrier_id` BIGINT COMMENT 'Reference to the carrier or Third-Party Logistics (3PL) provider responsible for transporting the shipment on this leg. Links to the carrier master data. Used for carrier performance analysis and Service Level Agreement (SLA) compliance tracking.',
    `consignment_id` BIGINT COMMENT 'Reference to the shipment for which this ETA/ETD event was generated. Links to the shipment master record.',
    `network_node_id` BIGINT COMMENT 'Reference to the destination location (hub, terminal, warehouse, customer site) for this shipment leg. Links to the location master data. Used for Door-to-Door (D2D) transit time calculation and last-mile delivery zone assignment.',
    `driver_profile_id` BIGINT COMMENT 'Reference to the driver or operator responsible for transporting the shipment on this leg. Links to the workforce master data. Used for driver performance tracking and compliance with Hours of Service (HOS) regulations.',
    `hold_id` BIGINT COMMENT 'Foreign key linking to customs.customs_hold. Business justification: ETA predictions must account for customs holds to maintain accuracy. Required for predictive ETA adjustment when holds occur, customer notification of customs-related delays, and SLA impact analysis.',
    `plan_id` BIGINT COMMENT 'Reference to the route plan that governs this shipment leg. Links to the planned route configuration from SAP TM or Blue Yonder network design.',
    `plan_leg_id` BIGINT COMMENT 'Foreign key linking to route.plan_leg. Business justification: eta_event is a real-time and predictive ETA/ETD event record for a shipment leg. It already links to plan (plan_id) at the plan level, but ETA events are inherently leg-specific — each event tracks th',
    `primary_eta_location_node_network_node_id` BIGINT COMMENT 'Reference to the network node (hub, terminal, warehouse, Container Freight Station (CFS), Inland Container Depot (ICD), or delivery zone) where the shipment was located at the time of this event. Links to the network topology master data.',
    `shipment_leg_id` BIGINT COMMENT 'Reference to the specific shipment leg or route segment for which this ETA/ETD event applies. A shipment may have multiple legs across different transport modes.',
    `transport_asset_id` BIGINT COMMENT 'Reference to the specific vehicle (truck, trailer, aircraft, vessel) transporting the shipment on this leg. Links to the fleet master data. Used for fleet utilization analysis and Global Positioning System (GPS) tracking integration.',
    `actual_etd` TIMESTAMP COMMENT 'The actual recorded time of departure when the shipment left the origin location, hub, or intermediate node. Captured from GPS, carrier Electronic Data Interchange (EDI), or manual confirmation. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `actual_transit_time_hours` DECIMAL(18,2) COMMENT 'The actual transit time in hours for this shipment leg, calculated from actual Estimated Time of Departure (ETD) to actual Estimated Time of Arrival (ETA). Populated once the leg is completed. Used for Key Performance Indicator (KPI) reporting and continuous improvement.',
    `awb_number` STRING COMMENT 'The Air Waybill (AWB) number for air freight shipments. This is the Master Air Waybill (MAWB) or House Air Waybill (HAWB) number issued by the carrier or freight forwarder. Used for tracking and customs clearance.',
    `bol_number` STRING COMMENT 'The Bill of Lading (BOL) number for ocean or ground freight shipments. This is the Master Bill of Lading (MBL) or House Bill of Lading (HBL) number issued by the carrier or Non-Vessel Operating Common Carrier (NVOCC). Used for tracking and proof of shipment.',
    `container_number` STRING COMMENT 'The unique container number for Full Container Load (FCL) or Less Than Container Load (LCL) ocean freight shipments. Follows International Organization for Standardization (ISO) 6346 standard for container identification. Used for tracking and terminal handling.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this ETA/ETD event record was first created in the system. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX. Used for audit trail and data lineage tracking.',
    `current_predicted_eta` TIMESTAMP COMMENT 'The most recent predicted estimated time of arrival based on real-time tracking data, traffic conditions, weather, and predictive algorithms from FourKites or SAP TM. This is the current best estimate of when the shipment will arrive. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `customer_notification_sent_flag` BOOLEAN COMMENT 'Boolean indicator (True/False) that identifies whether a customer notification (email, SMS, Application Programming Interface (API) push) was sent for this ETA/ETD event. True indicates the customer was notified; False indicates no notification was sent. Used for customer communication audit and Service Level Agreement (SLA) compliance.',
    `customer_notification_timestamp` TIMESTAMP COMMENT 'The date and time when the customer notification was sent for this ETA/ETD event. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX. Used for audit trail and Service Level Agreement (SLA) compliance verification.',
    `customs_clearance_status` STRING COMMENT 'The current customs clearance status for cross-border shipments. Indicates whether the shipment is pending clearance, cleared, on hold, requires inspection, or has been released by customs authorities. Captured from Descartes Customs or Automated Manifest System (AMS) / Importer Security Filing (ISF) integration.. Valid values are `Pending|Cleared|Hold|Inspection Required|Released`',
    `delay_reason_code` STRING COMMENT 'A standardized code indicating the root cause of any delay or exception. Examples include weather, traffic, customs hold, mechanical failure, carrier capacity issue, or documentation error. Used for root cause analysis and carrier performance scorecarding.',
    `delay_reason_description` STRING COMMENT 'A free-text description providing additional context or details about the delay or exception. Captured from carrier Electronic Data Interchange (EDI) messages, driver notes, or customer service case logs.',
    `eta_variance_hours` DECIMAL(18,2) COMMENT 'The difference in hours between the original planned ETA and the current predicted ETA. Positive values indicate a delay; negative values indicate the shipment is ahead of schedule. Used for Service Level Agreement (SLA) monitoring and On-Time Delivery (OTD) / On-Time In-Full (OTIF) Key Performance Indicator (KPI) calculation.',
    `etd_variance_hours` DECIMAL(18,2) COMMENT 'The difference in hours between the original planned ETD and the actual ETD. Positive values indicate a late departure; negative values indicate an early departure. Used for root cause analysis of delays and transit time performance.',
    `event_source` STRING COMMENT 'The system or channel that generated this ETA/ETD event. Indicates whether the event originated from FourKites real-time visibility platform, SAP TM route planning, carrier Electronic Data Interchange (EDI), GPS tracking device, manual operator entry, Oracle TMS, or Blue Yonder supply chain planning. [ENUM-REF-CANDIDATE: FourKites|SAP TM|Carrier EDI|GPS|Manual|Oracle TMS|Blue Yonder — 7 candidates stripped; promote to reference product]',
    `event_timestamp` TIMESTAMP COMMENT 'The date and time when this ETA/ETD event was generated or recorded. Represents the moment the prediction or update was made. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `event_type` STRING COMMENT 'The type of ETA/ETD event being recorded. Distinguishes between estimated time of arrival updates, estimated time of departure updates, predictive ETA calculations, actual ETD confirmations, exception alerts, and on-time confirmations.. Valid values are `ETA Update|ETD Update|ETA Prediction|ETD Actual|Exception Alert|On-Time Confirmation`',
    `exception_flag` BOOLEAN COMMENT 'Boolean indicator (True/False) that identifies whether this ETA/ETD event represents an exception condition requiring attention. True indicates a delay, early arrival, or other deviation from the Service Level Agreement (SLA) or planned schedule. Used to trigger exception management workflows.',
    `exception_severity` STRING COMMENT 'The severity level of the exception condition. Critical indicates Service Level Agreement (SLA) breach or customer escalation required; High indicates significant delay; Medium indicates minor delay; Low indicates minimal impact; None indicates no exception.. Valid values are `Critical|High|Medium|Low|None`',
    `exception_type` STRING COMMENT 'The specific type of exception or status condition associated with this ETA/ETD event. Categorizes the nature of the deviation (delay, early arrival, on-time, weather delay, traffic delay, customs delay, mechanical failure, route deviation, carrier issue). Used for root cause analysis and Key Performance Indicator (KPI) reporting. [ENUM-REF-CANDIDATE: Delay|Early|On-Time|Weather Delay|Traffic Delay|Customs Delay|Mechanical Failure|Route Deviation|Carrier Issue — 9 candidates stripped; promote to reference product]',
    `location_latitude` DECIMAL(18,2) COMMENT 'The geographic latitude coordinate of the shipment or vehicle at the time this ETA/ETD event was generated. Captured from Global Positioning System (GPS) or Radio Frequency Identification (RFID) tracking devices. Used for real-time visibility and geofencing.',
    `location_longitude` DECIMAL(18,2) COMMENT 'The geographic longitude coordinate of the shipment or vehicle at the time this ETA/ETD event was generated. Captured from Global Positioning System (GPS) or Radio Frequency Identification (RFID) tracking devices. Used for real-time visibility and geofencing.',
    `original_planned_eta` TIMESTAMP COMMENT 'The initial planned estimated time of arrival as defined in the original route plan or shipment booking. This is the baseline ETA against which all subsequent updates and variances are measured. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `original_planned_etd` TIMESTAMP COMMENT 'The initial planned estimated time of departure as defined in the original route plan or shipment booking. This is the baseline ETD for the origin or intermediate hub. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `planned_transit_time_hours` DECIMAL(18,2) COMMENT 'The planned transit time in hours for this shipment leg as defined in the route plan or service corridor standard. Used as the baseline for On-Time Delivery (OTD) and transit time variance analysis.',
    `pod_status` STRING COMMENT 'The Proof of Delivery (POD) status for this shipment leg. Indicates whether the shipment has not been delivered, has been delivered, delivery was attempted, was refused by the consignee, was damaged, or was lost. Used for Electronic Proof of Delivery (ePOD) integration and claims processing.. Valid values are `Not Delivered|Delivered|Attempted|Refused|Damaged|Lost`',
    `pod_timestamp` TIMESTAMP COMMENT 'The date and time when Proof of Delivery (POD) was captured. This is the actual delivery timestamp recorded by the driver or Electronic Proof of Delivery (ePOD) system. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX. Used for On-Time Delivery (OTD) calculation and billing.',
    `prediction_confidence_score` DECIMAL(18,2) COMMENT 'A confidence score (0-100) indicating the reliability of the current predicted ETA. Higher scores indicate greater confidence based on historical accuracy, data quality, and real-time tracking signal strength. Generated by FourKites or SAP TM predictive algorithms.',
    `service_type` STRING COMMENT 'The service level or product type for this shipment. Indicates express parcel delivery, standard service, economy, same-day, next-day, freight forwarding, Less Than Truckload (LTL), Full Truckload (FTL), Full Container Load (FCL), or Less Than Container Load (LCL). Used for Service Level Agreement (SLA) determination and On-Time Delivery (OTD) measurement. [ENUM-REF-CANDIDATE: Express|Standard|Economy|Same-Day|Next-Day|Freight|LTL|FTL|FCL|LCL — 10 candidates stripped; promote to reference product]',
    `sla_breach_flag` BOOLEAN COMMENT 'Boolean indicator (True/False) that identifies whether this ETA/ETD event represents a Service Level Agreement (SLA) breach. True indicates the shipment will miss or has missed the committed delivery time; False indicates on-time or early. Used for Key Performance Indicator (KPI) dashboards and customer credits processing.',
    `sla_target_delivery_timestamp` TIMESTAMP COMMENT 'The committed delivery date and time as defined in the Service Level Agreement (SLA) or customer contract. This is the contractual deadline against which On-Time Delivery (OTD) and On-Time In-Full (OTIF) performance is measured. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `traffic_condition` STRING COMMENT 'A description of the traffic conditions at the time of the ETA/ETD event or along the route. Captured from traffic Application Programming Interface (API) integration, Global Positioning System (GPS) data, or driver reports. Used for delay analysis and dynamic route optimization.. Valid values are `Normal|Light|Moderate|Heavy|Severe|Blocked`',
    `transport_mode` STRING COMMENT 'The mode of transportation for this shipment leg. Indicates whether the leg is transported by air, ocean, road, rail, or multimodal combination. Aligns with International Air Transport Association (IATA) and International Maritime Organization (IMO) standards.. Valid values are `Air|Ocean|Road|Rail|Multimodal`',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this ETA/ETD event record was last updated in the system. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX. Used for audit trail and change tracking.',
    `weather_condition` STRING COMMENT 'A description of the weather conditions at the time of the ETA/ETD event or along the route. Examples include clear, rain, snow, fog, storm, hurricane. Captured from weather Application Programming Interface (API) integration or driver reports. Used for delay analysis and predictive modeling.',
    CONSTRAINT pk_eta_event PRIMARY KEY(`eta_event_id`)
) COMMENT 'Real-time and predictive ETA/ETD event record generated by FourKites or SAP TM for a shipment leg or route plan. Captures event timestamp, event source (FourKites, carrier EDI, GPS, manual), shipment reference, leg reference, original planned ETA, current predicted ETA, ETA variance (hours), ETD actual, location at time of event (lat/long, node), prediction confidence score, exception flag, and exception type (delay, early, on-time). SSOT for all ETA updates consumed by customer visibility portals, exception management, and OTD/OTIF KPI calculation.';

CREATE OR REPLACE TABLE `transport_shipping_ecm`.`route`.`hub_spoke_config` (
    `hub_spoke_config_id` BIGINT COMMENT 'Unique identifier for the hub-and-spoke network configuration record. Primary key.',
    `network_node_id` BIGINT COMMENT 'Reference to the central hub facility or terminal that serves as the consolidation and distribution center for this configuration. Links to the facility/node master data.',
    `tpl_provider_id` BIGINT COMMENT 'Foreign key linking to network.tpl_provider. Business justification: Hub consolidation operations frequently outsourced to 3PL providers. Required for operational accountability, cost allocation, performance tracking, and 3PL contract compliance validation. Essential f',
    `carrier_id` BIGINT COMMENT 'Reference to the primary carrier or 3PL partner assigned to operate this hub-spoke configuration. Links to carrier master data.',
    `depot_id` BIGINT COMMENT 'Foreign key linking to fleet.fleet_depot. Business justification: Hub-spoke configurations define which depots serve as spokes (in addition to hub_node_id); critical for fleet deployment planning, asset allocation, and last-mile service design.',
    `approval_status` STRING COMMENT 'Approval status of the configuration before it becomes active. Ensures governance and sign-off by network planning and operations leadership.. Valid values are `pending|approved|rejected`',
    `approved_by` STRING COMMENT 'Name or identifier of the person who approved this hub-spoke configuration for operational use.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when this hub-spoke configuration was approved. Supports audit trail and compliance reporting.',
    `carrier_allocation_strategy` STRING COMMENT 'Strategy for allocating carriers to hub-spoke lanes: dedicated carriers per lane, shared carrier pool, dynamic selection via TMS, or contract-based assignment.. Valid values are `dedicated|shared|dynamic|contract_based`',
    `config_code` STRING COMMENT 'Business identifier code for the hub-spoke configuration, used for external reference and reporting. Typically follows a naming convention combining region, service product, and version.. Valid values are `^[A-Z0-9_-]{4,20}$`',
    `config_name` STRING COMMENT 'Human-readable name describing the hub-spoke configuration, typically including geographic scope and service type (e.g., APAC Express Hub-Spoke Q1 2024).',
    `config_status` STRING COMMENT 'Current lifecycle status of the hub-spoke configuration. Only active configurations are used for operational route planning and shipment execution.. Valid values are `draft|active|suspended|expired|archived`',
    `config_version` STRING COMMENT 'Version number of this configuration. Incremented when the configuration is updated, supporting change tracking and audit trails.',
    `consolidation_cutoff_time` TIMESTAMP COMMENT 'Daily cutoff time (HH:MM format, hub local time) by which shipments must arrive at the hub to be included in the next consolidation cycle.',
    `consolidation_frequency` STRING COMMENT 'Frequency at which shipments are consolidated at the hub before distribution to spokes. Impacts inventory holding time and service level.. Valid values are `daily|twice_daily|weekly|on_demand|continuous`',
    `country_scope` STRING COMMENT 'Comma-separated list of ISO 3166-1 alpha-3 country codes covered by this hub-spoke configuration. Defines the geographic boundary for customs and trade compliance.. Valid values are `^[A-Z]{3}(,[A-Z]{3})*$`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this hub-spoke configuration record was first created in the system. Supports audit trail and data lineage.',
    `customs_clearance_required` BOOLEAN COMMENT 'Indicates whether customs clearance is required at the hub for cross-border shipments in this configuration. Triggers Descartes Customs integration.',
    `direct_lane_bypass_enabled` BOOLEAN COMMENT 'Indicates whether direct spoke-to-spoke or spoke-to-destination lanes are allowed when volume/weight thresholds are met, bypassing the hub.',
    `effective_end_date` DATE COMMENT 'Date on which this hub-spoke configuration expires or is superseded by a new configuration. Null indicates an open-ended configuration.',
    `effective_start_date` DATE COMMENT 'Date from which this hub-spoke configuration becomes active and is used for route planning and shipment execution. Supports temporal network design.',
    `ftz_zone_applicable` BOOLEAN COMMENT 'Indicates whether the hub operates within or has access to a Free Trade Zone, enabling duty deferral and trade compliance benefits.',
    `hub_capacity_pallets` STRING COMMENT 'Maximum handling capacity of the hub in standard pallet positions. Relevant for LTL, parcel, and e-commerce fulfillment operations.',
    `hub_capacity_teu` DECIMAL(18,2) COMMENT 'Maximum handling capacity of the hub in Twenty-foot Equivalent Units (TEU) for containerized freight. Used for capacity planning and network design.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time when this hub-spoke configuration record was last updated. Supports change tracking and audit compliance.',
    `max_hub_to_spoke_transit_hours` DECIMAL(18,2) COMMENT 'Maximum allowable transit time in hours from the hub to any spoke node. Critical for On-Time Delivery (OTD) and On-Time In-Full (OTIF) performance.',
    `max_spoke_to_hub_transit_hours` DECIMAL(18,2) COMMENT 'Maximum allowable transit time in hours from any spoke node to the hub. Used for SLA validation, route planning, and network design optimization.',
    `min_volume_threshold_cbm` DECIMAL(18,2) COMMENT 'Minimum shipment volume in cubic meters (CBM) required to bypass the hub and establish a direct lane from spoke to destination. Used for load optimization and cost efficiency.',
    `min_weight_threshold_kg` DECIMAL(18,2) COMMENT 'Minimum shipment weight in kilograms required to qualify for direct lane bypass, avoiding hub consolidation. Supports FTL and FCL optimization logic.',
    `modified_by` STRING COMMENT 'Identifier of the user or system that last modified this hub-spoke configuration record. Supports accountability and audit trails.',
    `network_design_model_code` STRING COMMENT 'Reference to the Blue Yonder network design model or optimization run that generated or validated this hub-spoke configuration.',
    `network_region` STRING COMMENT 'Geographic region or market area covered by this hub-spoke configuration (e.g., North America, APAC, EU West). Used for regional network planning and optimization.',
    `notes` STRING COMMENT 'Free-text notes or comments about this hub-spoke configuration, including special handling instructions, seasonal adjustments, or operational constraints.',
    `optimization_objective` STRING COMMENT 'Primary objective used by Blue Yonder and SAP TM for network optimization: minimize cost, maximize speed, maximize reliability, or balanced multi-objective.. Valid values are `cost|speed|reliability|balanced`',
    `predictive_eta_enabled` BOOLEAN COMMENT 'Indicates whether predictive ETA calculation using FourKites or Blue Yonder is enabled for this configuration, supporting proactive exception management.',
    `real_time_visibility_enabled` BOOLEAN COMMENT 'Indicates whether FourKites real-time visibility tracking is enabled for shipments routed through this hub-spoke configuration.',
    `service_product_scope` STRING COMMENT 'The service product line or business segment this hub-spoke configuration applies to. Determines operational rules, SLA targets, and routing logic.. Valid values are `express|freight|e-commerce|contract_logistics|last_mile|multi_service`',
    `sla_target_otd_percent` DECIMAL(18,2) COMMENT 'Target On-Time Delivery percentage for shipments routed through this hub-spoke configuration. Used for performance monitoring and carrier evaluation.',
    `sla_target_otif_percent` DECIMAL(18,2) COMMENT 'Target On-Time In-Full percentage for shipments routed through this hub-spoke configuration. Measures both timeliness and completeness of delivery.',
    `spoke_count` STRING COMMENT 'Total number of spoke nodes included in this hub-spoke configuration. Used for network complexity analysis and capacity planning.',
    `spoke_nodes_list` STRING COMMENT 'Comma-separated list of spoke node codes or identifiers that are served by this hub. Represents the delivery/pickup points connected to the hub in this configuration.',
    `sustainability_target_co2e_kg_per_shipment` DECIMAL(18,2) COMMENT 'Target carbon emissions in CO2e kilograms per shipment for this hub-spoke configuration. Supports CORSIA and EU ETS compliance and sustainability reporting.',
    `transport_mode` STRING COMMENT 'Primary mode of transportation used for hub-to-spoke and spoke-to-hub movements in this configuration. Aligns with freight forwarding mode definitions.. Valid values are `air|ocean|road|rail|multimodal`',
    CONSTRAINT pk_hub_spoke_config PRIMARY KEY(`hub_spoke_config_id`)
) COMMENT 'Configuration record defining the hub-and-spoke topology for a specific network region or service product. Captures hub node, spoke nodes list, service product scope (express, freight, e-commerce), transport mode, maximum spoke-to-hub transit time, consolidation frequency, minimum volume threshold for direct lane bypass, effective date range, and configuration status. Managed in SAP TM and Blue Yonder for network design. Distinct from service_corridor (which defines named multi-leg paths) — this defines the structural hub-spoke relationship.';

CREATE OR REPLACE TABLE `transport_shipping_ecm`.`route`.`lane_performance` (
    `lane_performance_id` BIGINT COMMENT 'Unique surrogate identifier for each lane-period performance measurement record in the Silver Layer lakehouse. Primary key for this operational measurement entity.',
    `carrier_id` BIGINT COMMENT 'Reference to the carrier (transport service provider) whose performance is being measured on this lane for the defined period. Supports carrier scorecard and selection analytics.',
    `carrier_service_id` BIGINT COMMENT 'Foreign key linking to network.carrier_service. Business justification: Performance metrics must be measured against specific service-level commitments (express vs. standard SLAs differ). Required for service-level SLA compliance reporting, carrier scorecard generation, a',
    `lane_id` BIGINT COMMENT 'Reference to the origin-destination lane master record that this performance measurement covers. Links to the route domain lane master.',
    `rate_card_id` BIGINT COMMENT 'Foreign key linking to pricing.rate_card. Business justification: Lane performance metrics inform rate card adjustments. Rate_card_id links performance to pricing decisions, enabling performance-based rate optimization, rate card effectiveness analysis, and dynamic ',
    `transit_time_standard_id` BIGINT COMMENT 'Foreign key linking to route.transit_time_standard. Business justification: lane_performance captures actual vs planned transit performance for a lane over a measurement period. Linking lane_performance to transit_time_standard via transit_time_standard_id enables direct comp',
    `actual_transit_hours` DECIMAL(18,2) COMMENT 'The measured average actual transit time in hours for shipments on this lane during the measurement period. Sourced from FourKites actuals and Oracle TMS freight audit data. Compared against planned_transit_hours to derive delay.',
    `avg_delay_hours` DECIMAL(18,2) COMMENT 'Average number of hours by which shipments on this lane exceeded the planned transit time during the measurement period. Positive values indicate late delivery; negative values indicate early delivery. Key input for SLA breach analysis.',
    `avg_dim_weight_kg` DECIMAL(18,2) COMMENT 'Average dimensional (volumetric) weight in kilograms per shipment on this lane during the measurement period. DIM weight is used by carriers to price low-density shipments. Sourced from Oracle TMS freight audit.',
    `avg_freight_cost` DECIMAL(18,2) COMMENT 'Average freight cost per shipment on this lane during the measurement period, in the reporting currency. Sourced from Oracle TMS freight audit. Used for cost-per-lane benchmarking and network optimization analysis.',
    `avg_shipment_weight_kg` DECIMAL(18,2) COMMENT 'Average actual gross weight in kilograms per shipment on this lane during the measurement period. Used for load optimization, carrier rate benchmarking, and CO2e intensity calculations.',
    `carrier_invoice_accuracy_rate` DECIMAL(18,2) COMMENT 'Proportion of carrier invoices for shipments on this lane that matched the contracted rate without dispute during the measurement period. Sourced from Oracle TMS freight audit. Supports carrier financial performance evaluation.',
    `carrier_performance_score` DECIMAL(18,2) COMMENT 'Composite carrier performance score for this lane-period, typically on a 0–100 scale, derived from OTD rate, OTIF rate, exception rate, and transit time adherence. Primary input for carrier scorecard and SAP TM carrier selection decisions.',
    `co2e_per_shipment_kg` DECIMAL(18,2) COMMENT 'Average CO2e emissions in kilograms per shipment on this lane during the measurement period. Calculated from fuel consumption, transport mode, and distance. Supports EU ETS, CORSIA, and GHG sustainability reporting.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the avg_freight_cost and total_freight_cost monetary fields on this record (e.g., USD, EUR, GBP).. Valid values are `^[A-Z]{3}$`',
    `customs_clearance_delay_hours` DECIMAL(18,2) COMMENT 'Average hours of delay attributable to customs clearance processes for shipments on this lane during the measurement period. Sourced from Descartes Customs. Used for cross-border lane performance root cause analysis.',
    `damage_rate` DECIMAL(18,2) COMMENT 'Proportion of shipments on this lane that incurred cargo damage during the measurement period, expressed as a decimal. Used for carrier liability assessment, insurance claims analysis, and lane risk scoring.',
    `destination_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the lane destination. Used for cross-border compliance, customs reporting, and geographic performance segmentation.. Valid values are `^[A-Z]{3}$`',
    `destination_location_code` STRING COMMENT 'Standardized code for the destination hub, port, airport, or facility of the lane (e.g., IATA airport code, UN/LOCODE). Identifies the arrival point for transit time and OTD measurement.. Valid values are `^[A-Z]{3,5}$`',
    `exception_count` STRING COMMENT 'Total number of shipment exceptions (delays, damages, misroutes, customs holds, etc.) recorded on this lane during the measurement period. Sourced from FourKites exception management. Triggers network optimization review.',
    `exception_rate` DECIMAL(18,2) COMMENT 'Proportion of shipments on this lane that incurred at least one exception during the measurement period, expressed as a decimal (exception_count / shipment_count). Used for lane risk scoring and network optimization triggers.',
    `folio_source` STRING COMMENT 'Identifies the primary operational system of record from which actuals for this lane-period measurement were sourced (FourKites, Oracle TMS, SAP TM, or manual entry). Supports data lineage and audit traceability.. Valid values are `foukites|oracle_tms|sap_tm|manual`',
    `foukites_tracking_coverage_rate` DECIMAL(18,2) COMMENT 'Proportion of shipments on this lane that had active FourKites real-time GPS/IoT tracking during the measurement period. Low coverage rates may indicate data quality issues in actuals-based metrics.',
    `last_mile_delay_hours` DECIMAL(18,2) COMMENT 'Average hours of delay attributable specifically to the last-mile delivery segment for shipments on this lane during the measurement period. Enables root cause decomposition of total delay into linehaul vs. last-mile components.',
    `measurement_period_end_date` DATE COMMENT 'The last calendar date of the performance measurement window for this lane-period record. Combined with measurement_period_start_date defines the exact reporting interval.',
    `measurement_period_start_date` DATE COMMENT 'The first calendar date of the performance measurement window for this lane-period record. Combined with measurement_period_end_date defines the exact reporting interval (e.g., weekly, monthly).',
    `measurement_status` STRING COMMENT 'Lifecycle status of this lane-period performance measurement record. Draft = initial load; Confirmed = validated by freight audit; Published = available for scorecard and SLA reporting; Superseded = replaced by a corrected record.. Valid values are `draft|confirmed|under_review|published|superseded`',
    `network_optimization_trigger` BOOLEAN COMMENT 'Indicates whether this lane-period measurement has triggered a network optimization review in Blue Yonder based on SLA breach, high exception rate, or cost threshold exceedance. True = optimization review triggered.',
    `on_time_shipment_count` STRING COMMENT 'Number of shipments on this lane that were delivered on or before the planned delivery date/time during the measurement period. Numerator for OTD rate calculation.',
    `origin_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the lane origin. Used for cross-border compliance, customs reporting, and geographic performance segmentation.. Valid values are `^[A-Z]{3}$`',
    `origin_location_code` STRING COMMENT 'Standardized code for the origin hub, port, airport, or facility of the lane (e.g., IATA airport code, UN/LOCODE). Identifies the departure point for transit time and OTD measurement.. Valid values are `^[A-Z]{3,5}$`',
    `otd_rate` DECIMAL(18,2) COMMENT 'Proportion of shipments on this lane delivered on or before the planned delivery date/time during the measurement period, expressed as a decimal (e.g., 0.9500 = 95%). Core KPI for SLA monitoring and carrier scorecard.',
    `otif_rate` DECIMAL(18,2) COMMENT 'Proportion of shipments on this lane delivered both on time and in full (no quantity shortfall) during the measurement period, expressed as a decimal. Composite SLA metric used for customer contract compliance and carrier evaluation.',
    `period_type` STRING COMMENT 'Granularity of the measurement window for this lane-period record. Determines the aggregation cadence used for SLA monitoring and carrier scorecard reporting.. Valid values are `daily|weekly|monthly|quarterly`',
    `planned_transit_hours` DECIMAL(18,2) COMMENT 'The contracted or standard planned transit time in hours for this lane as defined in the SLA or service corridor standard. Sourced from SAP TM route planning master data. Baseline for OTD and delay calculations.',
    `pod_completion_rate` DECIMAL(18,2) COMMENT 'Proportion of shipments on this lane for which an electronic Proof of Delivery (ePOD) was captured and confirmed during the measurement period. Supports compliance with customer SLA documentation requirements.',
    `predictive_eta_accuracy_rate` DECIMAL(18,2) COMMENT 'Proportion of shipments on this lane for which FourKites predictive ETA was within the agreed tolerance window of the actual delivery time during the measurement period. Measures the reliability of the real-time visibility platforms ETA predictions.',
    `record_created_timestamp` TIMESTAMP COMMENT 'Timestamp when this lane-period performance measurement record was first created in the Silver Layer lakehouse. Supports data lineage, audit trail, and incremental processing.',
    `record_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this lane-period performance measurement record was last modified in the Silver Layer lakehouse. Used for change tracking, SLA audit, and incremental ETL processing.',
    `shipment_count` STRING COMMENT 'Total number of shipments executed on this lane during the measurement period. Denominator for OTD, OTIF, and exception rate calculations. Sourced from Oracle TMS shipment execution records.',
    `sla_breach_flag` BOOLEAN COMMENT 'Indicates whether the lanes OTD rate fell below the contracted SLA threshold (sla_threshold_otd) during the measurement period. True = SLA breached; False = SLA met. Triggers escalation and network optimization review workflows.',
    `sla_threshold_otd` DECIMAL(18,2) COMMENT 'The contracted minimum OTD rate threshold for this lane as defined in the applicable SLA or carrier agreement, expressed as a decimal (e.g., 0.9500 = 95%). Used to determine SLA compliance status for the period.',
    `source_system_record_reference` STRING COMMENT 'The native record identifier from the operational source system (FourKites or Oracle TMS) from which this lane-period measurement was extracted. Enables back-tracing to the system of record for audit and reconciliation.',
    `total_co2e_kg` DECIMAL(18,2) COMMENT 'Total CO2e emissions in kilograms for all shipments on this lane during the measurement period. Aggregate of co2e_per_shipment_kg × shipment_count. Used for sustainability reporting and carbon offset calculations.',
    `total_freight_cost` DECIMAL(18,2) COMMENT 'Total freight cost for all shipments on this lane during the measurement period, in the reporting currency. Sourced from Oracle TMS freight audit and SAP S/4HANA Finance. Used for P&L lane-level cost analysis.',
    `transport_mode` STRING COMMENT 'Primary mode of transport for this lane (air, ocean, road, rail, or multimodal). Aligns with IATA for air, IMO for ocean, and DOT for road/rail classifications.. Valid values are `air|ocean|road|rail|multimodal`',
    CONSTRAINT pk_lane_performance PRIMARY KEY(`lane_performance_id`)
) COMMENT 'Operational performance record for a lane over a defined measurement period, capturing actual vs. planned transit time, OTD rate, OTIF rate, average delay hours, shipment volume, exception count, carrier performance score, and CO2e per shipment for that lane. Sourced from FourKites actuals and Oracle TMS freight audit data. Used for lane-level SLA monitoring, carrier scorecard inputs, and network optimization trigger analysis. This is an operational measurement record, not an analytics aggregate — each row represents a lane-period measurement.';

CREATE OR REPLACE TABLE `transport_shipping_ecm`.`route`.`carrier_schedule` (
    `carrier_schedule_id` BIGINT COMMENT 'Unique surrogate identifier for the carrier schedule record in the Transport Shipping lakehouse Silver layer. Primary key for this entity.',
    `carrier_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.carrier_agreement. Business justification: Carrier schedules (vessel/flight rotations) operate under specific carrier agreements defining rates, capacity, and service terms. Essential for schedule-to-contract reconciliation, rate validation, a',
    `carrier_id` BIGINT COMMENT 'Reference to the carrier (shipping line, airline, road carrier, or rail operator) that operates this schedule. Used by SAP TM for carrier selection and Oracle TMS for freight audit.',
    `carrier_service_id` BIGINT COMMENT 'Foreign key linking to network.carrier_service. Business justification: Carrier schedules represent specific service offerings (express, economy, etc.). Link enables service-level performance tracking, rate application, and SLA validation against contracted service commit',
    `network_node_id` BIGINT COMMENT 'Reference to the network node (port, airport, hub, depot, ICD, CFS) at which this schedule arrives. Used for ETA/ETD management and last-mile delivery zone assignment.',
    `lane_id` BIGINT COMMENT 'Reference to the origin-destination lane master record that this schedule serves. Links the schedule to the route domain lane definition for load optimization and carrier selection in SAP TM and Oracle TMS.',
    `primary_carrier_network_node_id` BIGINT COMMENT 'Reference to the network node (port, airport, hub, depot, ICD, CFS) from which this schedule departs. Supports hub-and-spoke topology and FourKites real-time visibility integration.',
    `tariff_id` BIGINT COMMENT 'Foreign key linking to pricing.tariff. Business justification: Carrier schedules reference tariffs for published rates. Tariff_id links schedule to pricing, enabling schedule-based tariff rate lookup, carrier schedule costing, and published rate validation agains',
    `alliance_code` STRING COMMENT 'Code identifying the ocean carrier alliance (e.g., 2M, THE Alliance, Ocean Alliance) or air cargo alliance to which this schedule belongs. Used for slot-sharing and co-loading capacity management in Blue Yonder and Oracle TMS.',
    `arrival_days_of_week` STRING COMMENT 'Comma-separated list of ISO weekday numbers (1=Monday through 7=Sunday) on which this schedule arrives at the destination node. May differ from departure days for multi-day transits. Used for ETA calculation and last-mile delivery zone scheduling.',
    `arrival_time` TIMESTAMP COMMENT 'Scheduled local arrival time at the destination node in HH:mm (24-hour) format. Combined with arrival_days_of_week to determine the Estimated Time of Arrival (ETA) for delivery planning and SLA entitlement matching.',
    `arrival_timezone` STRING COMMENT 'IANA timezone identifier for the destination node (e.g., Europe/Rotterdam, Asia/Tokyo). Required to convert local arrival time to UTC for cross-border ETA management and FourKites real-time visibility integration.',
    `capacity_teu` DECIMAL(18,2) COMMENT 'Maximum container capacity of this schedule expressed in Twenty-foot Equivalent Units (TEU). Applicable for ocean FCL/LCL services. Null for non-ocean modes. Used for load optimization in Oracle TMS and capacity planning in Blue Yonder.',
    `capacity_volume_cbm` DECIMAL(18,2) COMMENT 'Maximum volumetric capacity in Cubic Meters (CBM) for this schedule. Used alongside DIM Weight (Dimensional Weight) calculations for air freight and LTL/LCL load optimization in Oracle TMS.',
    `capacity_weight_kg` DECIMAL(18,2) COMMENT 'Maximum payload weight capacity in kilograms for this schedule. Applicable across all transport modes (air, ocean, road, rail). Used for load optimization in Oracle TMS and freight order management in SAP TM.',
    `co2e_emission_factor` DECIMAL(18,2) COMMENT 'Carrier-published or calculated Carbon Dioxide Equivalent (CO2e) emission factor for this schedule in kg CO2e per tonne-km. Used for GHG (Greenhouse Gas) reporting, EU ETS compliance, CORSIA carbon offsetting calculations, and sustainability analytics.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this carrier schedule record was first ingested into the Transport Shipping lakehouse Silver layer. Audit trail field for data lineage and SOX compliance.',
    `cutoff_hours_before_departure` DECIMAL(18,2) COMMENT 'Cargo receipt deadline expressed as the number of hours before scheduled departure by which cargo must be tendered to the carrier at the origin node. Used by SAP TM for freight order management and Oracle TMS for shipment execution planning.',
    `dangerous_goods_accepted` BOOLEAN COMMENT 'Indicates whether this carrier schedule accepts dangerous goods (DG) shipments (True) or not (False). Drives compliance routing in Descartes Customs and shipment eligibility checks against IMDG Code (ocean) and ICAO Technical Instructions (air).',
    `departure_days_of_week` STRING COMMENT 'Comma-separated list of ISO weekday numbers (1=Monday through 7=Sunday) on which this schedule departs (e.g., 1,3,5 for Mon/Wed/Fri). Used by SAP TM for departure planning and Blue Yonder for network optimization.',
    `departure_time` TIMESTAMP COMMENT 'Scheduled local departure time at the origin node in HH:mm (24-hour) format. Combined with departure_days_of_week to determine the Estimated Time of Departure (ETD) for shipment planning in SAP TM and Oracle TMS.',
    `departure_timezone` STRING COMMENT 'IANA timezone identifier for the origin node (e.g., America/New_York, Asia/Shanghai). Required to convert local departure time to UTC for cross-border schedule coordination and FourKites predictive ETA calculation.',
    `destination_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the destination node (e.g., GBR, SGP, BRA). Used for import customs declaration routing in Descartes Customs, denied party screening, and WTO trade compliance.. Valid values are `^[A-Z]{3}$`',
    `destination_port_code` STRING COMMENT 'UN/LOCODE (5-character) for ocean/road/rail destinations or IATA 3-letter airport code for air destinations. Denormalised from the destination network node for EDI messaging, customs filing, and carrier schedule matching.. Valid values are `^[A-Z]{2}[A-Z0-9]{3}$`',
    `doc_cutoff_hours_before_departure` DECIMAL(18,2) COMMENT 'Deadline for submission of shipping documents (AWB, BOL, customs declarations) expressed as hours before scheduled departure. Required for Descartes Customs AMS/ISF filing compliance and carrier EDI submission.',
    `edi_source_code` STRING COMMENT 'Identifier of the EDI feed or carrier data exchange channel from which this schedule record was sourced (e.g., EDIFACT IFTMCS, ANSI X12 204, carrier API). Used for data lineage, reconciliation, and Silver layer ingestion audit in the Databricks lakehouse.',
    `effective_from_date` DATE COMMENT 'Calendar date from which this carrier schedule is valid and available for booking. Used for schedule versioning, seasonal service management, and SAP TM departure planning.',
    `effective_until_date` DATE COMMENT 'Calendar date after which this carrier schedule is no longer valid. Null indicates an open-ended schedule with no defined end date. Used for schedule lifecycle management and carrier contract alignment.',
    `frequency_per_week` STRING COMMENT 'Number of departures per week for this schedule on the specified lane. Used by Blue Yonder for supply chain planning, capacity allocation, and network design optimization.',
    `fuel_type` STRING COMMENT 'Primary fuel type used by the vessel, aircraft, or vehicle operating this schedule. Used for BAF (Bunker Adjustment Factor) surcharge calculation, GHG emissions reporting, and EU ETS compliance. [ENUM-REF-CANDIDATE: VLSFO|HFO|MGO|LNG|SAF|DIESEL|ELECTRIC|HYBRID — promote to reference product]',
    `is_direct_service` BOOLEAN COMMENT 'Indicates whether this schedule operates as a direct (non-stop) service between origin and destination nodes (True) or involves intermediate port calls / transshipment stops (False). Used for transit time accuracy and customer SLA commitments.',
    `origin_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the origin node (e.g., CHN, USA, DEU). Used for trade compliance routing in Descartes Customs, C-TPAT/AEO screening, and cross-border regulatory reporting.. Valid values are `^[A-Z]{3}$`',
    `origin_port_code` STRING COMMENT 'UN/LOCODE (5-character) for ocean/road/rail origins or IATA 3-letter airport code for air origins. Denormalised from the origin network node for EDI messaging, AMS filing, and carrier schedule matching without requiring a node lookup.. Valid values are `^[A-Z]{2}[A-Z0-9]{3}$`',
    `published_timestamp` TIMESTAMP COMMENT 'Timestamp when the carrier published or last updated this schedule via EDI feed. Represents the principal business event time for this record. Used for schedule freshness validation and EDI reconciliation in the Databricks Silver layer.',
    `ref` STRING COMMENT 'Carriers own internal reference or booking system identifier for this schedule, as received via EDI. Enables round-trip reconciliation with the carriers system and supports freight audit in Oracle TMS.',
    `schedule_number` STRING COMMENT 'Externally-known carrier schedule reference number or code as published by the carrier via EDI feed. Used as the business identifier for matching against carrier EDI messages (e.g., EDIFACT IFTMCS) and for reconciliation in SAP TM and Oracle TMS.',
    `schedule_status` STRING COMMENT 'Current lifecycle status of the carrier schedule record. ACTIVE: available for booking and departure planning. SUSPENDED: temporarily unavailable (e.g., port congestion, force majeure). CANCELLED: permanently discontinued. DRAFT: pending carrier confirmation. EXPIRED: past effective_until_date.. Valid values are `ACTIVE|SUSPENDED|CANCELLED|DRAFT|EXPIRED`',
    `schedule_version` STRING COMMENT 'Monotonically incrementing version number for this carrier schedule record, incremented each time the carrier publishes an updated schedule via EDI. Supports schedule change management and historical comparison in the Silver layer.',
    `temperature_controlled` BOOLEAN COMMENT 'Indicates whether this schedule provides temperature-controlled (reefer/cold chain) capacity (True) or ambient-only service (False). Used for perishable cargo eligibility and specialized equipment allocation in SAP TM.',
    `transit_time_hours` DECIMAL(18,2) COMMENT 'Standard published transit time in hours from origin node departure to destination node arrival for this schedule. Used as the baseline for SLA (Service Level Agreement) commitments, OTD (On-Time Delivery) KPI measurement, and Blue Yonder network optimization.',
    `transport_mode` STRING COMMENT 'Primary mode of transport for this carrier schedule. Drives carrier selection logic in SAP TM, load optimization in Oracle TMS, and customs declaration routing in Descartes Customs.. Valid values are `AIR|OCEAN|ROAD|RAIL|MULTIMODAL`',
    `transshipment_port_code` STRING COMMENT 'UN/LOCODE of the primary transshipment hub for indirect services (is_direct_service = False). Used for multi-leg ETA calculation, customs transit declaration in Descartes Customs, and FourKites milestone tracking.. Valid values are `^[A-Z]{2}[A-Z0-9]{3}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this carrier schedule record was last modified in the Transport Shipping lakehouse Silver layer. Used for incremental processing, change data capture, and audit trail maintenance.',
    `vgm_cutoff_hours_before_departure` DECIMAL(18,2) COMMENT 'Deadline for submission of Verified Gross Mass (VGM) declaration expressed as hours before scheduled departure. Mandatory for ocean shipments under SOLAS Amendment 2016. Null for non-ocean modes.',
    `voyage_rotation_number` STRING COMMENT 'Carrier-assigned voyage or rotation number for ocean services, or equivalent rotation identifier for air/rail. Used for Bill of Lading (BOL) and Master Bill of Lading (MBL) cross-referencing and port authority reporting.',
    CONSTRAINT pk_carrier_schedule PRIMARY KEY(`carrier_schedule_id`)
) COMMENT 'Published carrier schedule for a specific lane or corridor leg, capturing carrier reference, service name, origin node, destination node, transport mode, vessel/flight/train service identifier, departure day(s) of week, departure time, arrival day(s) of week, arrival time, frequency, transit time (hours), capacity (TEU/kg/CBM), cut-off time (cargo receipt deadline), effective date range, and schedule status. Sourced from carrier EDI feeds and used by SAP TM for departure planning and Oracle TMS for load optimization.';

